def _mail_templates(db: Session) -> list[MailTemplate]:
    existing = {str(row.template_key or ""): row for row in db.query(MailTemplate).all()}
    created = False
    for payload in MAIL_TEMPLATE_DEFAULTS:
        key = str(payload.get("template_key") or "")
        row = existing.get(key)
        if row is None:
            row = MailTemplate(
                template_key=key,
                name=str(payload.get("name") or key),
                subject_template=str(payload.get("subject_template") or ""),
                body_template=str(payload.get("body_template") or ""),
                active=True,
                created_at=_utcnow_naive(),
            )
            db.add(row)
            created = True
            continue
        changed = False
        if not str(row.name or "").strip():
            row.name = str(payload.get("name") or key)
            changed = True
        if not str(row.subject_template or "").strip():
            row.subject_template = str(payload.get("subject_template") or "")
            changed = True
        if not str(row.body_template or "").strip():
            row.body_template = str(payload.get("body_template") or "")
            changed = True
        if changed:
            db.add(row)
    if created:
        db.flush()
    return db.query(MailTemplate).order_by(MailTemplate.active.desc(), MailTemplate.name.asc(), MailTemplate.id.asc()).all()


def _mail_render_template_text(text: str | None, context: dict[str, object]) -> str:
    result = str(text or "")
    for key, value in context.items():
        result = result.replace(f"{{{{ {key} }}}}", str(value or ""))
        result = result.replace(f"{{{{{key}}}}}", str(value or ""))
    return result.strip()


def _mail_attachment_abs_path(file_path: str | None) -> Path | None:
    rel = str(file_path or "").strip()
    if not rel:
        return None
    abs_path = ensure_dirs()["uploads"] / rel
    return abs_path if abs_path.exists() else None


def _mail_auto_target_flash_entry(db: Session, payload: dict[str, object]) -> dict[str, str]:
    case_id = _to_int(payload.get("case_id"), 0)
    customer_id = _to_int(payload.get("customer_id"), 0)
    subject = _crm_clean_text(payload.get("subject")) or "(ohne Betreff)"
    if case_id > 0:
        row = db.get(CrmCase, case_id)
        if row:
            return {
                "message": f"Mail automatisch zugeordnet: {row.case_no} | {row.title}",
                "link_url": f"/crm/vorgaenge/{int(row.id)}",
                "link_label": "Zum Vorgang",
            }
    if customer_id > 0:
        row = db.get(MasterCustomer, customer_id)
        if row:
            party = db.get(Party, int(row.party_id or 0))
            label = f"{row.customer_no_internal} | {party.display_name if party else 'Kunde'}"
            return {
                "message": f"Mail automatisch zugeordnet: {label}",
                "link_url": f"/crm/kunden/{int(row.id)}",
                "link_label": "Zum Kunden",
            }
    thread_id = _to_int(payload.get("thread_id"), 0)
    if thread_id > 0:
        return {
            "message": f"Mail automatisch erkannt: {subject}",
            "link_url": f"/mail/threads/{thread_id}",
            "link_label": "Zum Thread",
        }
    return {"message": f"Mail automatisch erkannt: {subject}", "link_url": "", "link_label": ""}


def _mail_customer_options(db: Session) -> list[dict[str, object]]:
    rows = db.query(MasterCustomer).order_by(MasterCustomer.customer_no_internal.asc(), MasterCustomer.id.asc()).limit(300).all()
    party_ids = [int(row.party_id) for row in rows]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    return [
        {
            "id": int(row.id),
            "label": f"{row.customer_no_internal} | {str(parties.get(int(row.party_id)).display_name if parties.get(int(row.party_id)) else '').strip() or '-'}",
        }
        for row in rows
    ]


def _mail_case_options(db: Session) -> list[dict[str, object]]:
    rows = db.query(CrmCase).order_by(CrmCase.id.desc()).limit(300).all()
    return [{"id": int(row.id), "label": f"{row.case_no} | {row.title}"} for row in rows]


def _mail_search_customer_rows(db: Session, q: str, limit: int = 16) -> list[dict[str, object]]:
    search = _crm_clean_text(q)
    if not search:
        return []
    like = f"%{search}%"
    rows = (
        db.query(MasterCustomer)
        .join(Party, Party.id == MasterCustomer.party_id)
        .outerjoin(CrmAddress, and_(CrmAddress.party_id == Party.id, CrmAddress.is_default == True))
        .outerjoin(CustomerContactPerson, CustomerContactPerson.master_customer_id == MasterCustomer.id)
        .filter(
            or_(
                MasterCustomer.customer_no_internal.ilike(like),
                Party.display_name.ilike(like),
                CrmAddress.email.ilike(like),
                CrmAddress.phone.ilike(like),
                CustomerContactPerson.email.ilike(like),
                CustomerContactPerson.phone.ilike(like),
            )
        )
        .order_by(MasterCustomer.customer_no_internal.asc(), MasterCustomer.id.asc())
        .limit(max(1, int(limit)))
        .all()
    )
    party_ids = [int(row.party_id) for row in rows]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids or [0])).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    return [
        {
            "id": int(row.id),
            "label": _crm_customer_label(row, parties.get(int(row.party_id)), default_map.get(int(row.party_id))),
            "customer": row,
            "party": parties.get(int(row.party_id)),
        }
        for row in rows
    ]


def _mail_search_case_rows(db: Session, q: str, *, customer_id: int = 0, limit: int = 16) -> list[dict[str, object]]:
    query = db.query(CrmCase)
    if int(customer_id or 0) > 0:
        query = query.join(RoleAssignment, RoleAssignment.case_id == CrmCase.id).filter(
            RoleAssignment.master_customer_id == int(customer_id),
            RoleAssignment.role_type.in_((CRM_ROLE_ORDERING_PARTY, CRM_ROLE_INVOICE_RECIPIENT)),
        )
    search = _crm_clean_text(q)
    if search:
        like = f"%{search}%"
        query = query.filter(or_(CrmCase.case_no.ilike(like), CrmCase.title.ilike(like), CrmCase.note.ilike(like)))
    rows = query.order_by(CrmCase.updated_at.desc(), CrmCase.id.desc()).limit(max(1, int(limit))).all()
    return [{"id": int(row.id), "label": f"{row.case_no} | {row.title}", "row": row} for row in rows]


def _mail_customer_label_map_by_ids(db: Session, customer_ids: list[int]) -> dict[int, str]:
    ids = sorted({int(value) for value in customer_ids if int(value or 0) > 0})
    if not ids:
        return {}
    rows = db.query(MasterCustomer).filter(MasterCustomer.id.in_(ids)).all()
    party_ids = [int(row.party_id) for row in rows]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids or [0])).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    return {
        int(row.id): _crm_customer_label(row, parties.get(int(row.party_id)), default_map.get(int(row.party_id)))
        for row in rows
    }


def _mail_case_label_map_by_ids(db: Session, case_ids: list[int]) -> dict[int, str]:
    ids = sorted({int(value) for value in case_ids if int(value or 0) > 0})
    if not ids:
        return {}
    rows = db.query(CrmCase).filter(CrmCase.id.in_(ids)).all()
    return {int(row.id): f"{row.case_no} | {row.title}" for row in rows}


def _mail_thread_spam_reason(latest: EmailMessage | None) -> str:
    if latest is None:
        return ""
    return probable_spam_reason(
        from_email=str(latest.from_email or ""),
        subject=str(latest.subject or ""),
        body_text=str(latest.body_text or latest.snippet or ""),
        to_emails=str(latest.to_emails or ""),
    )


def _mail_thread_latest_message_map(db: Session, thread_ids: list[int]) -> dict[int, EmailMessage]:
    out: dict[int, EmailMessage] = {}
    if not thread_ids:
        return out
    rows = (
        db.query(EmailMessage)
        .filter(EmailMessage.thread_id.in_(thread_ids))
        .order_by(func.coalesce(EmailMessage.received_at, EmailMessage.sent_at, EmailMessage.fetched_at).desc(), EmailMessage.id.desc())
        .all()
    )
    for row in rows:
        thread_id = int(row.thread_id or 0)
        if thread_id > 0 and thread_id not in out:
            out[thread_id] = row
    return out


def _mail_messages_for_thread(db: Session, thread_id: int) -> list[EmailMessage]:
    return (
        db.query(EmailMessage)
        .filter(EmailMessage.thread_id == int(thread_id))
        .order_by(func.coalesce(EmailMessage.received_at, EmailMessage.sent_at, EmailMessage.fetched_at).asc(), EmailMessage.id.asc())
        .all()
    )


def _mail_attachments_map(db: Session, message_ids: list[int]) -> dict[int, list[MailAttachment]]:
    out: dict[int, list[MailAttachment]] = {}
    if not message_ids:
        return out
    rows = (
        db.query(MailAttachment)
        .filter(MailAttachment.mail_message_id.in_(message_ids))
        .order_by(MailAttachment.id.asc())
        .all()
    )
    for row in rows:
        out.setdefault(int(row.mail_message_id), []).append(row)
    return out


def _mail_assign_thread(db: Session, thread: MailThread, *, customer_id: int | None, case_id: int | None, status: str = "assigned") -> None:
    customer_value = int(customer_id or 0)
    case_value = int(case_id or 0)
    if customer_value > 0:
        thread.master_customer_id = customer_value
    if case_value > 0:
        thread.case_id = case_value
    thread.status = "waiting" if status == "suggested" else "open"
    db.add(thread)
    message_rows = db.query(EmailMessage).filter(EmailMessage.thread_id == int(thread.id)).all()
    for row in message_rows:
        if customer_value > 0:
            row.master_customer_id = customer_value
        if case_value > 0:
            row.case_id = case_value
        row.assignment_status = status
        db.add(row)


def _mail_backfill_legacy_threads(db: Session, limit: int = 200) -> None:
    rows = (
        db.query(EmailMessage)
        .filter(EmailMessage.thread_id.is_(None))
        .order_by(EmailMessage.id.asc())
        .limit(max(1, int(limit)))
        .all()
    )
    for row in rows:
        suggestion = mail_suggest_assignments(
            db,
            from_email=str(row.from_email or ""),
            to_emails=str(row.to_emails or ""),
            cc_emails=str(row.cc_emails or ""),
            subject=str(row.subject or ""),
            body_text=str(row.body_text or row.snippet or ""),
            in_reply_to=str(row.in_reply_to or ""),
            references_header=str(row.references_header or ""),
            attachment_names=[],
        )
        customer_ids = list(suggestion.get("customer_ids") or [])
        case_ids = list(suggestion.get("case_ids") or [])
        thread = (
            db.get(MailThread, int(suggestion.get("thread_id") or 0))
            if int(suggestion.get("thread_id") or 0) > 0
            else None
        )
        if thread is None:
            subject_normalized = mail_normalize_subject(row.subject or row.snippet or f"Nachricht {row.id}")
            thread = (
                db.query(MailThread)
                .filter(MailThread.subject_normalized == subject_normalized)
                .order_by(MailThread.last_message_at.desc(), MailThread.id.desc())
                .first()
            )
        if thread is None:
            thread = MailThread(
                subject_normalized=mail_normalize_subject(row.subject or row.snippet or f"Nachricht {row.id}"),
                master_customer_id=customer_ids[0] if len(customer_ids) == 1 else (int(row.master_customer_id or 0) or None),
                case_id=case_ids[0] if len(case_ids) == 1 else (int(row.case_id or 0) or None),
                status="open",
                last_message_at=row.received_at or row.sent_at or row.fetched_at or _utcnow_naive(),
                created_at=row.fetched_at or _utcnow_naive(),
            )
            db.add(thread)
            db.flush()
        row.thread_id = int(thread.id)
        if len(customer_ids) == 1 and int(row.master_customer_id or 0) <= 0:
            row.master_customer_id = int(customer_ids[0])
        if len(case_ids) == 1 and int(row.case_id or 0) <= 0:
            row.case_id = int(case_ids[0])
        row.assignment_status = str(suggestion.get("status") or row.assignment_status or "unassigned")
        if int(thread.master_customer_id or 0) <= 0 and int(row.master_customer_id or 0) > 0:
            thread.master_customer_id = int(row.master_customer_id)
        if int(thread.case_id or 0) <= 0 and int(row.case_id or 0) > 0:
            thread.case_id = int(row.case_id)
        thread.last_message_at = row.received_at or row.sent_at or row.fetched_at or thread.last_message_at or _utcnow_naive()
        db.add(thread)
        db.add(row)
    if rows:
        db.flush()


def _mail_thread_rows(
    db: Session,
    *,
    q: str = "",
    status: str = "",
    assignment: str = "",
    limit: int = 120,
    show_spam: bool = False,
) -> list[dict[str, object]]:
    _mail_backfill_legacy_threads(db, limit=300)
    query = db.query(MailThread)
    status_norm = (status or "").strip().lower()
    if status_norm in ("open", "waiting", "closed"):
        query = query.filter(MailThread.status == status_norm)
    rows = query.order_by(func.coalesce(MailThread.last_message_at, MailThread.created_at).desc(), MailThread.id.desc()).limit(max(1, int(limit))).all()
    latest_map = _mail_thread_latest_message_map(db, [int(row.id) for row in rows])
    out: list[dict[str, object]] = []
    q_norm = (q or "").strip().lower()
    assignment_norm = (assignment or "").strip().lower()
    customers = {int(row.id): row for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_([int(item.master_customer_id) for item in rows if int(item.master_customer_id or 0) > 0])).all()} if rows else {}
    cases = {int(row.id): row for row in db.query(CrmCase).filter(CrmCase.id.in_([int(item.case_id) for item in rows if int(item.case_id or 0) > 0])).all()} if rows else {}
    party_ids = [int(row.party_id) for row in customers.values()]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    for row in rows:
        latest = latest_map.get(int(row.id))
        spam_reason = _mail_thread_spam_reason(latest)
        search_blob = " ".join(
            [
                str(latest.subject if latest else ""),
                str(latest.from_email if latest else ""),
                str(row.subject_normalized or ""),
                str(cases.get(int(row.case_id or 0)).case_no if cases.get(int(row.case_id or 0)) else ""),
                str(customers.get(int(row.master_customer_id or 0)).customer_no_internal if customers.get(int(row.master_customer_id or 0)) else ""),
                str(parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)).display_name if customers.get(int(row.master_customer_id or 0)) and parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)) else ""),
            ]
        ).lower()
        if q_norm and q_norm not in search_blob:
            continue
        if spam_reason and not bool(show_spam):
            continue
        if assignment_norm == "unassigned" and (int(row.master_customer_id or 0) > 0 or int(row.case_id or 0) > 0):
            continue
        if assignment_norm == "assigned" and int(row.master_customer_id or 0) <= 0 and int(row.case_id or 0) <= 0:
            continue
        out.append(
            {
                "thread": row,
                "latest": latest,
                "customer": customers.get(int(row.master_customer_id or 0)),
                "customer_party": parties.get(int(customers.get(int(row.master_customer_id or 0)).party_id or 0)) if customers.get(int(row.master_customer_id or 0)) else None,
                "crm_case": cases.get(int(row.case_id or 0)),
                "spam_reason": spam_reason,
            }
        )
    return out


def _document_search_blob(item: DocumentInboxItem) -> str:
    parts = [str(item.title or ""), str(item.correspondent or ""), str(item.document_type or "")]
    try:
        meta = json.loads(item.metadata_json or "{}")
        if isinstance(meta, dict):
            for key in ("content", "ocr", "title", "original_file_name", "correspondent_name"):
                value = meta.get(key)
                if value not in (None, ""):
                    parts.append(str(value))
    except Exception:
        pass
    return "\n".join(parts)


def _paperless_customer_candidate_items(db: Session, customer_id: int, limit: int = 12) -> list[DocumentInboxItem]:
    linked_doc_ids = {
        str(row.paperless_document_id or "").strip()
        for row in _paperless_links_for_object(db, "customer", int(customer_id))
        if str(row.paperless_document_id or "").strip()
    }
    rows = (
        db.query(DocumentInboxItem)
        .filter(
            DocumentInboxItem.suggested_object_type == "customer",
            DocumentInboxItem.suggested_object_id == int(customer_id),
            DocumentInboxItem.status != "matched",
        )
        .all()
    )
    filtered = [row for row in rows if str(row.paperless_document_id or "").strip() not in linked_doc_ids]
    filtered.sort(
        key=lambda row: (
            -int(_json_dict(row.metadata_json).get("customer_scan", {}).get("score") or 0),
            -int(_json_dict(row.metadata_json).get("customer_scan", {}).get("priority_rank") or 0),
            -(int((row.created_date or dt.datetime.min).timestamp()) if row.created_date else 0),
            -int(row.id or 0),
        ),
        reverse=False,
    )
    return filtered[: max(1, int(limit or 12))]


def _paperless_af_sa_ref_token(value: str | None) -> str:
    text = _crm_clean_text(value).upper()
    if not text:
        return ""
    match = re.search(r"\b((?:AF|SA)[\s/_-]*\d{2,})\b", text)
    if not match:
        return ""
    return re.sub(r"[^A-Z0-9]", "", match.group(1))


def _paperless_customer_name_terms(party: Party, contact_rows: list[dict[str, object]] | None = None) -> list[str]:
    terms: list[str] = []
    seen: set[str] = set()

    def add_term(value: str | None) -> None:
        text = _crm_clean_text(value)
        if len(text) < 3:
            return
        key = _crm_normalize_key(text)
        if key in seen:
            return
        seen.add(key)
        terms.append(text)

    def add_name_variants(value: str | None) -> None:
        text = _crm_clean_text(value)
        if not text:
            return
        add_term(text)
        parts = [part for part in re.split(r"\s+", text) if _crm_clean_text(part)]
        if len(parts) >= 2:
            add_term(parts[-1])

    add_name_variants(party.display_name)
    for item in list(contact_rows or [])[:6]:
        party_row = item.get("party")
        if party_row:
            add_name_variants(getattr(party_row, "display_name", None))
    return terms[:6]


def _paperless_customer_outsmart_refs(db: Session, customer_id: int, limit: int = 12) -> list[str]:
    refs: list[str] = []
    seen: set[str] = set()

    def add_ref(value: str | None) -> None:
        token = _paperless_af_sa_ref_token(value)
        if not token or token in seen:
            return
        seen.add(token)
        refs.append(token)

    local_rows = (
        db.query(OutsmartWorkorder)
        .filter(OutsmartWorkorder.master_customer_id == int(customer_id))
        .order_by(OutsmartWorkorder.updated_at.desc(), OutsmartWorkorder.id.desc())
        .limit(max(1, int(limit)))
        .all()
    )
    for row in local_rows:
        payload = _json_dict(row.raw_json)
        add_ref(row.workorder_no)
        add_ref(payload.get("JobNr"))
        add_ref(payload.get("Reference"))
        add_ref(payload.get("ExternalReference"))
        add_ref(payload.get("OrderNr"))
    for item in _customer_outsmart_stage_workorder_rows(db, int(customer_id), limit=max(1, int(limit))):
        row = item.get("row")
        if not row:
            continue
        payload = _json_dict(getattr(row, "raw_json", ""))
        add_ref(getattr(row, "workorder_no", None))
        add_ref(payload.get("JobNr"))
        add_ref(payload.get("Reference"))
        add_ref(payload.get("ExternalReference"))
        add_ref(payload.get("OrderNr"))
    return refs[: max(1, int(limit))]


def _paperless_customer_search_terms(
    db: Session,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
) -> list[str]:
    terms: list[str] = []
    seen: set[str] = set()

    def add_term(value: str | None, *, min_len: int = 4) -> None:
        text = _crm_clean_text(value)
        if len(text) < min_len:
            return
        key = _crm_normalize_key(text)
        if key in seen:
            return
        seen.add(key)
        terms.append(text)

    name_terms = _paperless_customer_name_terms(party, contact_rows)
    workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=8)
    if name_terms and workorder_refs:
        for ref in workorder_refs[:8]:
            for name_term in name_terms[:4]:
                add_term(f"{name_term} {ref}", min_len=6)
                add_term(f"{ref} {name_term}", min_len=6)
        return terms[:12]

    add_term(customer.customer_no_internal, min_len=3)
    for name_term in name_terms:
        add_term(name_term)
    if default_address:
        add_term(default_address.email, min_len=6)
        add_term(default_address.phone, min_len=6)
        zip_city = _crm_clean_text(f"{default_address.zip_code or ''} {default_address.city or ''}")
        add_term(zip_city, min_len=8)
    for row in identities:
        add_term(row.external_key, min_len=4)
        add_term(row.external_id, min_len=4)
    for item in list(contact_rows or [])[:4]:
        row = item.get("row")
        party_row = item.get("party")
        if party_row:
            add_term(getattr(party_row, "display_name", None))
        if row:
            add_term(getattr(row, "email", None), min_len=6)
            add_term(getattr(row, "phone", None), min_len=6)
    return terms[:8]


def _paperless_customer_topic_boost(text: str) -> tuple[int, list[str]]:
    blob = _crm_normalize_key(text)
    if not blob:
        return 0, []
    topics = [
        ("Rechnung", ("rechnung", "invoice", "re26", "re24")),
        ("Angebot", ("angebot", "order", "an-", "angebotnr")),
        ("Auftrag", ("auftrag", "bestellung", "arbeitsauftrag")),
        ("Kundendienst", ("kundendienst", "service", "reparatur", "wartung")),
    ]
    score = 0
    reasons: list[str] = []
    for label, keys in topics:
        if any(key in blob for key in keys):
            score += 2
            reasons.append(label)
    return score, reasons


def _paperless_customer_match_score(
    *,
    text: str,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
    workorder_refs: list[str] | None = None,
) -> tuple[int, list[str]]:
    blob = _crm_normalize_key(text)
    score = 0
    reasons: list[str] = []
    if not blob:
        return score, reasons

    def hit(value: str | None) -> bool:
        key = _crm_normalize_key(value)
        return bool(key) and key in blob

    name_hits: list[str] = []
    for value in _paperless_customer_name_terms(party, contact_rows):
        if hit(value):
            name_hits.append(value)
    ref_hits: list[str] = []
    for value in list(workorder_refs or [])[:12]:
        if _crm_normalize_key(value) and _crm_normalize_key(value) in blob:
            ref_hits.append(value)

    if list(workorder_refs or []):
        if not name_hits or not ref_hits:
            return 0, []
        score += 6
        reasons.append("Name")
        score += 8
        reasons.append("AF/SA-Nummer")

    if hit(customer.customer_no_internal):
        score += 6
        reasons.append("Kundennummer")
    if hit(party.display_name):
        score += 5
        reasons.append("Anzeigename")
    if default_address:
        if _crm_normalize_email(default_address.email) and _crm_normalize_email(default_address.email) in blob:
            score += 6
            reasons.append("E-Mail")
        if hit(default_address.zip_code) and hit(default_address.city):
            score += 2
            reasons.append("PLZ/Ort")
    for row in identities:
        key = _crm_clean_text(row.external_key or row.external_id)
        if len(key) >= 4 and hit(key):
            score += 4
            reasons.append(f"{_crm_external_system_label(row.system_name)}-Kennung")
            break
    for item in list(contact_rows or [])[:4]:
        row = item.get("row")
        party_row = item.get("party")
        if party_row and hit(getattr(party_row, "display_name", None)):
            score += 3
            reasons.append("Ansprechpartner")
            break
        if row and _crm_normalize_email(getattr(row, "email", None)) and _crm_normalize_email(getattr(row, "email", None)) in blob:
            score += 3
            reasons.append("Kontakt-Mail")
            break
    topic_score, topic_reasons = _paperless_customer_topic_boost(text)
    score += topic_score
    for label in topic_reasons:
        reasons.append(f"Dokumenttyp: {label}")
    return score, reasons


def _paperless_scan_customer_documents(
    db: Session,
    *,
    customer: MasterCustomer,
    party: Party,
    default_address: CrmAddress | None,
    identities: list[ExternalIdentity],
    contact_rows: list[dict[str, object]] | None = None,
    limit: int = 16,
) -> dict[str, int]:
    settings = _paperless_settings(db, include_secret=True)
    if not bool(settings.get("enabled")) or not bool(settings.get("token")):
        raise ValueError("Paperless ist nicht aktiviert oder es fehlt das API-Token.")
    workorder_refs = _paperless_customer_outsmart_refs(db, int(customer.id), limit=8)
    terms = _paperless_customer_search_terms(db, customer, party, default_address, identities, contact_rows)
    if not terms:
        return {"queries": 0, "fetched": 0, "suggested": 0}
    linked_doc_ids = {
        str(row.paperless_document_id or "").strip()
        for row in _paperless_links_for_object(db, "customer", int(customer.id))
        if str(row.paperless_document_id or "").strip()
    }
    fetched = 0
    suggested = 0
    seen_doc_ids: set[str] = set()
    per_query_limit = max(8, min(int(limit or 16), 24))
    for term in terms:
        rows = paperless_list_documents(settings, limit=per_query_limit, query=term)
        for payload in rows:
            document_id = str(payload.get("id") or payload.get("document_id") or "").strip()
            if not document_id or document_id in seen_doc_ids or document_id in linked_doc_ids:
                continue
            seen_doc_ids.add(document_id)
            item = _upsert_document_inbox_item(db, payload)
            if item is None:
                continue
            fetched += 1
            if str(item.status or "").strip() == "matched":
                continue
            score, reasons = _paperless_customer_match_score(
                text=_document_search_blob(item),
                customer=customer,
                party=party,
                default_address=default_address,
                identities=identities,
                contact_rows=contact_rows,
                workorder_refs=workorder_refs,
            )
            if score < 5:
                continue
            _, topic_reasons = _paperless_customer_topic_boost(_document_search_blob(item))
            priority_rank = 0
            if "Rechnung" in topic_reasons:
                priority_rank = 4
            elif "Angebot" in topic_reasons:
                priority_rank = 3
            elif "Auftrag" in topic_reasons:
                priority_rank = 2
            elif "Kundendienst" in topic_reasons:
                priority_rank = 1
            item.suggested_object_type = "customer"
            item.suggested_object_id = int(customer.id)
            meta = _json_dict(item.metadata_json)
            meta["customer_scan"] = {
                "customer_id": int(customer.id),
                "score": score,
                "reasons": reasons,
                "priority_rank": priority_rank,
                "topic_reasons": topic_reasons,
                "workorder_refs": workorder_refs[:8],
            }
            item.metadata_json = json.dumps(meta, ensure_ascii=False)
            db.add(item)
            suggested += 1
    return {"queries": len(terms), "fetched": fetched, "suggested": suggested}


def _document_match_candidates(db: Session, item: DocumentInboxItem) -> dict[str, list[object]]:
    text = _document_search_blob(item).lower()
    customers = []
    for row in db.query(MasterCustomer).order_by(MasterCustomer.id.desc()).limit(200).all():
        if str(row.customer_no_internal or "").lower() in text:
            customers.append(row)
    cases = []
    for row in db.query(CrmCase).order_by(CrmCase.id.desc()).limit(200).all():
        if str(row.case_no or "").lower() in text:
            cases.append(row)
    repairs = []
    for row in db.query(RepairOrder).order_by(RepairOrder.id.desc()).limit(200).all():
        if str(row.repair_no or "").lower() in text:
            repairs.append(row)
    orders = []
    for row in db.query(PurchaseOrder).order_by(PurchaseOrder.id.desc()).limit(200).all():
        tokens = [str(row.po_number or "").lower(), str(row.order_no or "").lower()]
        if any(token and token in text for token in tokens):
            orders.append(row)
    receipts = []
    for row in db.query(GoodsReceipt).order_by(GoodsReceipt.id.desc()).limit(200).all():
        if str(row.receipt_no or "").lower() in text:
            receipts.append(row)
    invoices = []
    for row in db.query(PurchaseInvoice).order_by(PurchaseInvoice.id.desc()).limit(200).all():
        if str(row.invoice_no or "").lower() in text:
            invoices.append(row)
    return {
        "customers": customers[:20],
        "cases": cases[:20],
        "repairs": repairs[:20],
        "orders": orders[:20],
        "receipts": receipts[:20],
        "invoices": invoices[:20],
    }


def _document_timeline_targets(db: Session, object_type: str, object_id: int) -> dict[str, int | None]:
    kind = str(object_type or "").strip()
    if kind == "customer":
        return {"master_customer_id": int(object_id), "case_id": None}
    if kind == "case":
        row = db.get(CrmCase, int(object_id))
        customer_id = None
        if row:
            role = (
                db.query(RoleAssignment)
                .filter(RoleAssignment.case_id == int(row.id), RoleAssignment.role_type == CRM_ROLE_ORDERING_PARTY)
                .first()
            )
            customer_id = int(role.master_customer_id or 0) or None if role else None
        return {"master_customer_id": customer_id, "case_id": int(object_id)}
    if kind == "repair_order":
        return {"master_customer_id": None, "case_id": None}
    return {"master_customer_id": None, "case_id": None}


def _document_timeline_add(
    db: Session,
    *,
    object_type: str,
    object_id: int,
    title: str,
    paperless_document_id: str | None = None,
    external_ref: str | None = None,
) -> None:
    targets = _document_timeline_targets(db, object_type, object_id)
    if int(targets.get("master_customer_id") or 0) <= 0 and int(targets.get("case_id") or 0) <= 0:
        return
    ref = external_ref or (f"paperless:{paperless_document_id}" if paperless_document_id else f"{object_type}:{object_id}:{title}")
    exists = (
        db.query(CrmTimelineEvent)
        .filter(CrmTimelineEvent.source_system == "paperless", CrmTimelineEvent.external_ref == ref)
        .first()
    )
    if exists:
        return
    db.add(
        CrmTimelineEvent(
            case_id=int(targets.get("case_id") or 0) or None,
            master_customer_id=int(targets.get("master_customer_id") or 0) or None,
            source_system="paperless",
            event_type="document",
            title=title,
            body=f"Dokument zugeordnet: {object_type} #{int(object_id)}",
            event_ts=_utcnow_naive(),
            external_ref=ref,
            meta_json=json.dumps({"paperless_document_id": paperless_document_id or "", "object_type": object_type, "object_id": int(object_id)}, ensure_ascii=False),
            created_at=_utcnow_naive(),
        )
    )


def _store_uploaded_attachment(
    *,
    entity_type: str,
    entity_id: int,
    upload: UploadFile,
) -> Attachment:
    original_name = Path(str(upload.filename or "").strip()).name or "dokument"
    safe_name = re.sub(r"[^A-Za-z0-9._-]+", "_", original_name).strip("._") or "dokument"
    rel_dir = Path("documents") / str(entity_type) / str(int(entity_id))
    abs_dir = ensure_dirs()["uploads"] / rel_dir
    abs_dir.mkdir(parents=True, exist_ok=True)
    file_name = f"{dt.datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{uuid.uuid4().hex[:8]}_{safe_name}"
    abs_path = abs_dir / file_name
    payload = upload.file.read() or b""
    abs_path.write_bytes(payload)
    return Attachment(
        entity_type=str(entity_type),
        entity_id=int(entity_id),
        filename=str(rel_dir / file_name),
        original_name=original_name,
        mime_type=str(upload.content_type or "application/octet-stream"),
        size_bytes=len(payload),
        created_at=_utcnow_naive(),
    )


def _attachments_for_entity(db: Session, entity_type: str, entity_id: int) -> list[Attachment]:
    return (
        db.query(Attachment)
        .filter(Attachment.entity_type == str(entity_type), Attachment.entity_id == int(entity_id))
        .order_by(Attachment.id.desc())
        .all()
    )


def _json_dict(raw: str | None) -> dict[str, object]:
    try:
        payload = json.loads(raw or "{}")
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def _document_object_url(object_type: str, object_id: int) -> str:
    mapping = {
        "customer": f"/crm/kunden/{int(object_id)}",
        "case": f"/crm/vorgaenge/{int(object_id)}",
        "purchase_order": f"/einkauf/bestellungen/{int(object_id)}",
        "goods_receipt": f"/einkauf/wareneingaenge/{int(object_id)}",
        "purchase_invoice": f"/einkauf/rechnungen/{int(object_id)}",
        "supplier": f"/stammdaten/lieferanten/{int(object_id)}",
        "repair_order": f"/inventory/reparaturen/{int(object_id)}",
        "supplier_condition_set": f"/einkauf/konditionen/{int(object_id)}",
    }
    return mapping.get(str(object_type or "").strip(), "")


def _document_object_exists(db: Session, object_type: str, object_id: int) -> bool:
    target_id = int(object_id or 0)
    if target_id <= 0:
        return False
    mapping = {
        "customer": MasterCustomer,
        "case": CrmCase,
        "purchase_order": PurchaseOrder,
        "goods_receipt": GoodsReceipt,
        "purchase_invoice": PurchaseInvoice,
        "supplier": Supplier,
        "repair_order": RepairOrder,
        "supplier_condition_set": SupplierConditionSet,
    }
    model = mapping.get(str(object_type or "").strip())
    return bool(model and db.get(model, target_id))


def _document_object_label(db: Session, object_type: str, object_id: int) -> str:
    target_id = int(object_id or 0)
    if target_id <= 0:
        return "-"
    kind = str(object_type or "").strip()
    if kind == "customer":
        row = db.get(MasterCustomer, target_id)
        if not row:
            return "-"
        party = db.get(Party, int(row.party_id))
        return f"{row.customer_no_internal} | {party.display_name if party else 'Kunde'}"
    if kind == "case":
        row = db.get(CrmCase, target_id)
        return f"{row.case_no} | {row.title}" if row else "-"
    if kind == "purchase_order":
        row = db.get(PurchaseOrder, target_id)
        return (row.order_no or row.po_number) if row else "-"
    if kind == "goods_receipt":
        row = db.get(GoodsReceipt, target_id)
        return (row.receipt_no or f"WE-{target_id:06d}") if row else "-"
    if kind == "purchase_invoice":
        row = db.get(PurchaseInvoice, target_id)
        return row.invoice_no if row else "-"
    if kind == "supplier":
        row = db.get(Supplier, target_id)
        return row.name if row else "-"
    if kind == "repair_order":
        row = db.get(RepairOrder, target_id)
        return row.repair_no or f"REP-{target_id:06d}" if row else "-"
    if kind == "supplier_condition_set":
        row = db.get(SupplierConditionSet, target_id)
        return row.name if row else "-"
    return f"{kind} #{target_id}"


def _document_link_item_to_target(
    db: Session,
    *,
    item: DocumentInboxItem,
    object_type: str,
    object_id: int,
) -> None:
    target_type = str(object_type or "").strip()
    target_id = int(object_id or 0)
    if not _document_object_exists(db, target_type, target_id):
        raise ValueError("Zielobjekt wurde nicht gefunden.")
    _link_inbox_item_to_object(db, item=item, object_type=target_type, object_id=target_id)
    if target_type == "purchase_order":
        row = db.get(PurchaseOrder, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
    elif target_type == "goods_receipt":
        row = db.get(GoodsReceipt, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)
    elif target_type == "purchase_invoice":
        row = db.get(PurchaseInvoice, target_id)
        if row and not str(row.paperless_document_id or "").strip():
            row.paperless_document_id = item.paperless_document_id
            db.add(row)


def _document_inbox_item_from_paperless_id(db: Session, paperless_document_id: str | None) -> DocumentInboxItem | None:
    document_id = str(paperless_document_id or "").strip()
    if not document_id:
        return None
    return (
        db.query(DocumentInboxItem)
        .filter(DocumentInboxItem.paperless_document_id == document_id)
        .order_by(DocumentInboxItem.id.desc())
        .first()
    )


def _upsert_uploaded_document_item(
    db: Session,
    *,
    paperless_document_id: str,
    title: str,
    object_type: str,
    object_id: int,
    metadata: dict[str, object] | None = None,
) -> DocumentInboxItem:
    row = _document_inbox_item_from_paperless_id(db, paperless_document_id)
    if row is None:
        row = DocumentInboxItem(
            paperless_document_id=str(paperless_document_id),
            created_at=_utcnow_naive(),
        )
    row.title = str(title or "").strip() or row.title
    row.status = "matched"
    row.suggested_object_type = str(object_type or "").strip() or None
    row.suggested_object_id = int(object_id or 0) or None
    row.created_date = row.created_date or _utcnow_naive()
    row.metadata_json = json.dumps(metadata or {}, ensure_ascii=False) if metadata else row.metadata_json
    db.add(row)
    db.flush()
    return row


def _crm_first_service_location(db: Session, customer_id: int) -> ServiceLocation | None:
    if int(customer_id or 0) <= 0:
        return None
    return (
        db.query(ServiceLocation)
        .filter(ServiceLocation.master_customer_id == int(customer_id), ServiceLocation.active == True)
        .order_by(ServiceLocation.id.asc())
        .first()
    )


def _mail_thread_subject(thread: MailThread | None, messages: list[EmailMessage]) -> str:
    for row in reversed(messages):
        text = str(row.subject or "").strip()
        if text:
            return text
    subject = str(thread.subject_normalized if thread else "").strip()
    return subject or "(ohne Betreff)"


def _mail_default_recipient(db: Session, customer: MasterCustomer | None, crm_case: CrmCase | None = None) -> str:
    target_customer = customer
    if target_customer is None and crm_case is not None:
        role = (
            db.query(RoleAssignment)
            .filter(RoleAssignment.case_id == int(crm_case.id), RoleAssignment.role_type == CRM_ROLE_ORDERING_PARTY)
            .first()
        )
        if role and int(role.master_customer_id or 0) > 0:
            target_customer = db.get(MasterCustomer, int(role.master_customer_id))
    if target_customer is None:
        return ""
    contact = (
        db.query(CustomerContactPerson)
        .filter(
            CustomerContactPerson.master_customer_id == int(target_customer.id),
            CustomerContactPerson.active == True,
            CustomerContactPerson.email.is_not(None),
        )
        .order_by(CustomerContactPerson.id.asc())
        .first()
    )
    if contact and str(contact.email or "").strip():
        return str(contact.email or "").strip()
    default_address = (
        db.query(CrmAddress)
        .filter(CrmAddress.party_id == int(target_customer.party_id), CrmAddress.active == True)
        .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
        .first()
    )
    return str(default_address.email or "").strip() if default_address else ""


BACKGROUND_JOB_ACTIVE_STATUSES = ("queued", "running")
BACKGROUND_JOB_POLL_INTERVAL_SECONDS = 1.0
BACKGROUND_JOB_HEARTBEAT_TIMEOUT_SECONDS = 300


def _sync_job_progress_payload(raw: str | None) -> dict[str, object]:
    return _json_dict(raw)


def _sync_job_set_progress(row: ExternalSyncJob, payload: dict[str, object]) -> None:
    row.progress_json = json.dumps(payload, ensure_ascii=False) if payload else None


def _sync_job_progress_merge(row: ExternalSyncJob, updates: dict[str, object]) -> dict[str, object]:
    payload = _sync_job_progress_payload(row.progress_json)
    for key, value in updates.items():
        if value is None:
            continue
        payload[str(key)] = value
    _sync_job_set_progress(row, payload)
    return payload


def _sync_job_log_append_text(existing: str | None, text: str | None) -> str | None:
    current = str(existing or "").strip()
    addition = str(text or "").strip()
    if not addition:
        return current or None
    if not current:
        return addition
    if addition in current:
        return current
    return f"{current}\n{addition}"


def _sync_job_title_default(entity_type: str, system_name: str = "") -> str:
    mapping = {
        "customer_init_outsmart": "OutSmart-Initialimport",
        "customer_init_sevdesk": "sevDesk-Initialimport",
        "customer_init_matching": "Kunden-Matching",
        "customer_init_ai_review": "KI-Review Kunden-Initialisierung",
        "customer_init_materialize": "Master-Kunden erzeugen",
        "catalog_import_run": "CSV-Katalogimport",
    }
    key = str(entity_type or "").strip().lower()
    if key in mapping:
        return mapping[key]
    system = str(system_name or "").strip()
    if system:
        return f"{system}: {entity_type}"
    return str(entity_type or "Hintergrundjob")


def _sync_job_eta_seconds(row: ExternalSyncJob, progress: dict[str, object]) -> int | None:
    total_count = _to_int(progress.get("total_count"), 0)
    processed_count = _to_int(progress.get("processed_count"), 0)
    if total_count <= 0 or processed_count <= 0 or not row.started_at:
        return None
    elapsed = max(0.0, (_utcnow_naive() - row.started_at).total_seconds())
    if elapsed <= 0:
        return None
    rate = processed_count / elapsed
    if rate <= 0:
        return None
    remaining = max(0, total_count - processed_count)
    return int(round(remaining / rate))


def _sync_job_view(row: ExternalSyncJob) -> dict[str, object]:
    progress = _sync_job_progress_payload(row.progress_json)
    return {
        "id": int(row.id),
        "job_key": str(row.job_key or ""),
        "lock_key": str(row.lock_key or ""),
        "title": str(row.title or _sync_job_title_default(row.entity_type, row.system_name)),
        "system_name": str(row.system_name or ""),
        "direction": str(row.direction or ""),
        "entity_type": str(row.entity_type or ""),
        "status": str(row.status or ""),
        "queued_at": row.queued_at.isoformat() if row.queued_at else None,
        "started_at": row.started_at.isoformat() if row.started_at else None,
        "heartbeat_at": row.heartbeat_at.isoformat() if row.heartbeat_at else None,
        "finished_at": row.finished_at.isoformat() if row.finished_at else None,
        "log_text": str(row.log_text or ""),
        "result_url": str(row.result_url or ""),
        "progress": progress,
        "eta_seconds": _sync_job_eta_seconds(row, progress),
    }


def _start_sync_job(
    db: Session,
    *,
    system_name: str,
    direction: str,
    entity_type: str,
    log_text: str = "",
    status: str = "running",
    job_key: str = "",
    lock_key: str = "",
    title: str = "",
    progress: dict[str, object] | None = None,
    result_url: str = "",
) -> ExternalSyncJob:
    now = _utcnow_naive()
    normalized_status = str(status or "running").strip().lower() or "running"
    row = ExternalSyncJob(
        system_name=str(system_name),
        direction=str(direction),
        entity_type=str(entity_type),
        job_key=str(job_key or "").strip() or None,
        lock_key=str(lock_key or "").strip() or None,
        title=str(title or "").strip() or _sync_job_title_default(entity_type, system_name),
        status=normalized_status,
        queued_at=now,
        started_at=now if normalized_status == "running" else None,
        heartbeat_at=now if normalized_status == "running" else None,
        result_url=str(result_url or "").strip() or None,
        progress_json=json.dumps(progress or {}, ensure_ascii=False) if progress else None,
        log_text=(log_text or "").strip() or None,
    )
    db.add(row)
    db.flush()
    return row


def _finish_sync_job(db: Session, row: ExternalSyncJob, *, status: str, log_text: str, result_url: str | None = None) -> None:
    row.status = str(status)
    row.finished_at = _utcnow_naive()
    row.heartbeat_at = row.finished_at
    row.log_text = (log_text or "").strip() or row.log_text
    if result_url is not None:
        row.result_url = str(result_url or "").strip() or None
    db.add(row)


def _sync_job_update_progress(
    db: Session,
    row: ExternalSyncJob,
    *,
    phase: str | None = None,
    phase_detail: str | None = None,
    total_count: int | None = None,
    processed_count: int | None = None,
    success_count: int | None = None,
    error_count: int | None = None,
    local_decision_count: int | None = None,
    openai_decision_count: int | None = None,
    cached_decision_count: int | None = None,
    current_item_label: str | None = None,
    current_item_ref: str | None = None,
    note: str | None = None,
    log_text: str | None = None,
    result_url: str | None = None,
    commit: bool = False,
) -> dict[str, object]:
    updates: dict[str, object] = {
        "phase": str(phase or "").strip() or None,
        "phase_detail": str(phase_detail or "").strip() or None,
        "total_count": int(total_count) if total_count is not None and int(total_count) >= 0 else None,
        "processed_count": int(processed_count) if processed_count is not None and int(processed_count) >= 0 else None,
        "success_count": int(success_count) if success_count is not None and int(success_count) >= 0 else None,
        "error_count": int(error_count) if error_count is not None and int(error_count) >= 0 else None,
        "local_decision_count": int(local_decision_count) if local_decision_count is not None and int(local_decision_count) >= 0 else None,
        "openai_decision_count": int(openai_decision_count) if openai_decision_count is not None and int(openai_decision_count) >= 0 else None,
        "cached_decision_count": int(cached_decision_count) if cached_decision_count is not None and int(cached_decision_count) >= 0 else None,
        "current_item_label": str(current_item_label or "").strip() or None,
        "current_item_ref": str(current_item_ref or "").strip() or None,
        "note": str(note or "").strip() or None,
    }
    payload = _sync_job_progress_merge(row, updates)
    row.heartbeat_at = _utcnow_naive()
    if log_text:
        row.log_text = _sync_job_log_append_text(row.log_text, log_text)
    if result_url is not None:
        row.result_url = str(result_url or "").strip() or None
    db.add(row)
    if commit:
        db.commit()
    else:
        db.flush()
    return payload


def _sync_job_existing_active(db: Session, *, lock_key: str = "", job_key: str = "") -> ExternalSyncJob | None:
    query = db.query(ExternalSyncJob).filter(ExternalSyncJob.status.in_(BACKGROUND_JOB_ACTIVE_STATUSES))
    if str(job_key or "").strip():
        row = query.filter(ExternalSyncJob.job_key == str(job_key).strip()).order_by(ExternalSyncJob.id.desc()).first()
        if row is not None:
            return row
    if str(lock_key or "").strip():
        row = query.filter(ExternalSyncJob.lock_key == str(lock_key).strip()).order_by(ExternalSyncJob.id.desc()).first()
        if row is not None:
            return row
    return None


def _enqueue_sync_job(
    db: Session,
    *,
    system_name: str,
    direction: str,
    entity_type: str,
    title: str,
    job_key: str,
    lock_key: str,
    log_text: str = "",
    progress: dict[str, object] | None = None,
    result_url: str = "",
) -> tuple[ExternalSyncJob, bool]:
    existing = _sync_job_existing_active(db, lock_key=lock_key, job_key=job_key)
    if existing is not None:
        return existing, False
    row = _start_sync_job(
        db,
        system_name=system_name,
        direction=direction,
        entity_type=entity_type,
        log_text=log_text,
        status="queued",
        job_key=job_key,
        lock_key=lock_key,
        title=title,
        progress=progress,
        result_url=result_url,
    )
    return row, True


def _latest_sync_job_for_key(db: Session, job_key: str) -> ExternalSyncJob | None:
    key = str(job_key or "").strip()
    if not key:
        return None
    return db.query(ExternalSyncJob).filter(ExternalSyncJob.job_key == key).order_by(ExternalSyncJob.id.desc()).first()


def _background_job_recover_stale_running_jobs() -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        rows = db.query(ExternalSyncJob).filter(ExternalSyncJob.status == "running").all()
        changed = False
        for row in rows:
            row.status = "failed"
            row.finished_at = _utcnow_naive()
            row.heartbeat_at = row.finished_at
            row.log_text = _sync_job_log_append_text(row.log_text, "Hintergrundjob wurde nach App-Neustart als abgebrochen markiert.")
            db.add(row)
            changed = True
        if changed:
            db.commit()
        else:
            db.rollback()
    except Exception:
        db.rollback()
    finally:
        db.close()


def _background_job_claim_next_id() -> int:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = (
            db.query(ExternalSyncJob)
            .filter(ExternalSyncJob.status == "queued")
            .order_by(case((ExternalSyncJob.queued_at.is_(None), 1), else_=0), ExternalSyncJob.queued_at.asc(), ExternalSyncJob.id.asc())
            .first()
        )
        if row is None:
            return 0
        if str(row.lock_key or "").strip():
            active_same_lock = (
                db.query(ExternalSyncJob)
                .filter(
                    ExternalSyncJob.id != int(row.id),
                    ExternalSyncJob.lock_key == str(row.lock_key or "").strip(),
                    ExternalSyncJob.status == "running",
                )
                .count()
            )
            if active_same_lock:
                db.rollback()
                return 0
        row.status = "running"
        row.started_at = row.started_at or _utcnow_naive()
        row.heartbeat_at = _utcnow_naive()
        db.add(row)
        db.commit()
        return int(row.id)
    except Exception:
        db.rollback()
        return 0
    finally:
        db.close()


def _background_job_fail(job_id: int, message: str) -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = db.get(ExternalSyncJob, int(job_id))
        if row is None:
            db.rollback()
            return
        _finish_sync_job(db, row, status="failed", log_text=message)
        db.commit()
    except Exception:
        db.rollback()
    finally:
        db.close()


def _run_background_job_by_id(job_id: int) -> None:
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        row = db.get(ExternalSyncJob, int(job_id))
        if row is None:
            db.rollback()
            return
        job_key = str(row.job_key or "").strip()
        if job_key == "customer_init_outsmart":
            _customer_init_import_outsmart(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_sevdesk":
            _customer_init_import_sevdesk(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_matching":
            _customer_init_build_clusters(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_ai_review":
            _customer_init_ai_review_clusters(db, job=row)
            db.commit()
            return
        if job_key == "customer_init_materialize":
            _customer_init_materialize_ready_clusters(db, job=row)
            db.commit()
            return
        if job_key.startswith("catalog_import_run:"):
            _catalog_import_execute_job(db, row)
            db.commit()
            return
        raise ValueError(f"Unbekannter Hintergrundjob: {job_key or row.entity_type}")
    except Exception as exc:
        db.rollback()
        _background_job_fail(int(job_id), str(exc))
    finally:
        db.close()


async def _background_job_loop():
    await asyncio.to_thread(_background_job_recover_stale_running_jobs)
    while True:
        try:
            job_id = await asyncio.to_thread(_background_job_claim_next_id)
            if job_id <= 0:
                await asyncio.sleep(BACKGROUND_JOB_POLL_INTERVAL_SECONDS)
                continue
            await asyncio.to_thread(_run_background_job_by_id, int(job_id))
        except asyncio.CancelledError:
            raise
        except Exception:
            await asyncio.sleep(BACKGROUND_JOB_POLL_INTERVAL_SECONDS)


def _upsert_external_link(
    db: Session,
    *,
    system_name: str,
    object_type: str,
    object_id: int,
    external_key: str,
    external_row_id: str | None = None,
    deep_link_url: str | None = None,
) -> ExternalLink:
    row = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == str(system_name),
            ExternalLink.object_type == str(object_type),
            ExternalLink.object_id == int(object_id),
        )
        .one_or_none()
    )
    if not row:
        row = ExternalLink(
            system_name=str(system_name),
            object_type=str(object_type),
            object_id=int(object_id),
            external_key=str(external_key),
            external_row_id=(external_row_id or "").strip() or None,
            deep_link_url=(deep_link_url or "").strip() or None,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
    else:
        row.external_key = str(external_key)
        row.external_row_id = (external_row_id or "").strip() or row.external_row_id
        row.deep_link_url = (deep_link_url or "").strip() or row.deep_link_url
        row.updated_at = _utcnow_naive()
    db.add(row)
    db.flush()
    return row


def _build_plaintext_export(title: str, lines: list[str]) -> Path:
    temp_dir = Path(tempfile.mkdtemp(prefix="kda_einkauf_"))
    target = temp_dir / f"{slugify(title) or 'dokument'}.txt"
    target.write_text("\n".join(lines).strip() + "\n", encoding="utf-8")
    return target


def _mobile_display_name(product: Product | None) -> str:
    if not product:
        return ""
    item_type = _normalize_item_type(getattr(product, "item_type", ""), fallback="material")
    if item_type == "appliance":
        sales_name = str(getattr(product, "sales_name", "") or "").strip()
        if sales_name:
            return sales_name
    name = str(getattr(product, "name", "") or "").strip()
    if name:
        return name
    return f"Produkt {int(getattr(product, 'id', 0) or 0)}"


def _mobile_manufacturer_label(product: Product | None, fallback_name: str = "") -> str:
    if not product:
        return str(fallback_name or "").strip()
    for value in (
        getattr(product, "manufacturer_name", ""),
        getattr(product, "manufacturer", ""),
        fallback_name,
    ):
        text = str(value or "").strip()
        if text:
            return text
    return "-"


def _mobile_catalog_feature_filters(
    db: Session,
    *,
    kind_id: int,
    query_params,
) -> list[dict[str, object]]:
    selected_kind_id = int(kind_id or 0)
    if selected_kind_id <= 0:
        return []
    feature_defs = (
        db.query(FeatureDef)
        .filter(FeatureDef.device_kind_id == int(selected_kind_id), FeatureDef.filterable == True)
        .order_by(FeatureDef.label_de.asc(), FeatureDef.id.asc())
        .limit(24)
        .all()
    )
    filters: list[dict[str, object]] = []
    for feature_def in feature_defs:
        fid = int(feature_def.id)
        data_type = str(feature_def.data_type or "text")
        filter_row: dict[str, object] = {
            "id": fid,
            "label": str(feature_def.label_de or feature_def.key or f"Merkmal {fid}"),
            "data_type": data_type,
            "text_mode": "canonical",
            "value": "",
            "min": "",
            "max": "",
            "min_value": None,
            "max_value": None,
            "options": [],
            "min_options": [],
            "max_options": [],
            "bool_options": [],
        }
        if data_type == "number":
            number_values, has_more = _feature_filter_number_options(
                db,
                device_kind_id=int(selected_kind_id),
                feature_def_id=fid,
                limit=FEATURE_FILTER_OPTION_LIMIT,
            )
            number_options = [
                {"value": _format_feature_number_option(value), "label": _format_feature_number_option(value), "disabled": False}
                for value in number_values
            ]
            if has_more:
                number_options.append({"value": "", "label": "(weitere Werte vorhanden ...)", "disabled": True})
            filter_row["min_options"] = list(number_options)
            filter_row["max_options"] = list(number_options)

            raw_min = str(query_params.get(f"f_{fid}_min") or "").strip()
            raw_max = str(query_params.get(f"f_{fid}_max") or "").strip()
            min_selected = _resolve_number_filter_selection(raw_min, number_values)
            max_selected = _resolve_number_filter_selection(raw_max, number_values)

            min_label = str(min_selected[0]) if min_selected else ""
            max_label = str(max_selected[0]) if max_selected else ""
            min_value = float(min_selected[1]) if min_selected else None
            max_value = float(max_selected[1]) if max_selected else None
            if min_value is not None and max_value is not None and min_value > max_value:
                min_label, max_label = max_label, min_label
                min_value, max_value = max_value, min_value

            filter_row["min"] = min_label
            filter_row["max"] = max_label
            filter_row["min_value"] = min_value
            filter_row["max_value"] = max_value
        elif data_type == "bool":
            bool_values = _feature_filter_bool_options(db, device_kind_id=int(selected_kind_id), feature_def_id=fid)
            bool_options: list[dict[str, object]] = []
            if True in bool_values:
                bool_options.append({"value": "1", "label": "Ja", "disabled": False})
            if False in bool_values:
                bool_options.append({"value": "0", "label": "Nein", "disabled": False})
            filter_row["bool_options"] = bool_options
            raw_bool = str(query_params.get(f"f_{fid}") or "").strip().lower()
            if raw_bool in ("1", "true", "ja") and True in bool_values:
                filter_row["value"] = "1"
            elif raw_bool in ("0", "false", "nein") and False in bool_values:
                filter_row["value"] = "0"
        else:
            text_options, has_more, text_mode = _feature_filter_text_options(
                db,
                device_kind_id=int(selected_kind_id),
                feature_def_id=fid,
                limit=FEATURE_FILTER_OPTION_LIMIT,
            )
            filter_row["text_mode"] = text_mode
            options_for_ui = list(text_options)
            if has_more:
                options_for_ui.append({"value": "", "label": "(weitere Werte vorhanden ...)", "disabled": True, "option_id": 0})
            filter_row["options"] = options_for_ui

            raw_filter_value = str(query_params.get(f"f_{fid}") or "").strip()
            if text_mode == "legacy_text":
                if raw_filter_value:
                    selected_opt = next(
                        (
                            row
                            for row in text_options
                            if str(row.get("value") or "").strip().casefold() == raw_filter_value.casefold()
                        ),
                        None,
                    )
                    if selected_opt and not bool(selected_opt.get("disabled")):
                        filter_row["value"] = str(selected_opt.get("value") or "")
            else:
                raw_option_id = _to_int(raw_filter_value, 0)
                if raw_option_id > 0:
                    selected_opt = next(
                        (row for row in text_options if int(row.get("option_id") or 0) == int(raw_option_id)),
                        None,
                    )
                    if not selected_opt:
                        selected_row = (
                            db.query(FeatureOption.id, FeatureOption.label_de, FeatureOption.canonical_key, FeatureOption.active)
                            .filter(
                                FeatureOption.id == int(raw_option_id),
                                FeatureOption.feature_def_id == fid,
                            )
                            .one_or_none()
                        )
                        if selected_row and bool(selected_row[3]):
                            selected_label = str(selected_row[1] or "").strip() or str(selected_row[2] or "").strip()
                            selected_opt = {
                                "value": str(int(selected_row[0])),
                                "label": selected_label,
                                "disabled": False,
                                "option_id": int(selected_row[0]),
                            }
                            filter_row["options"] = [selected_opt] + options_for_ui
                    if selected_opt and not bool(selected_opt.get("disabled")):
                        filter_row["value"] = str(int(raw_option_id))
        filters.append(filter_row)
    return filters


def _mobile_catalog_apply_feature_filters(query, feature_filters: list[dict[str, object]]):
    for filter_row in feature_filters:
        fid = int(filter_row.get("id") or 0)
        if fid <= 0:
            continue
        data_type = str(filter_row.get("data_type") or "text")
        if data_type == "number":
            min_value_raw = filter_row.get("min_value")
            max_value_raw = filter_row.get("max_value")
            min_value = float(min_value_raw) if min_value_raw is not None else None
            max_value = float(max_value_raw) if max_value_raw is not None else None
            if min_value is not None:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_num.isnot(None),
                            FeatureValue.value_num >= min_value,
                        )
                    )
                )
            if max_value is not None:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_num.isnot(None),
                            FeatureValue.value_num <= max_value,
                        )
                    )
                )
            continue
        if data_type == "bool":
            value = str(filter_row.get("value") or "").strip()
            if value == "1":
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_bool == True,
                        )
                    )
                )
            elif value == "0":
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_bool == False,
                        )
                    )
                )
            continue
        text_mode = str(filter_row.get("text_mode") or "canonical").strip().lower()
        if text_mode == "legacy_text":
            selected_legacy_value = str(filter_row.get("value") or "").strip()
            if selected_legacy_value:
                query = query.filter(
                    exists().where(
                        and_(
                            FeatureValue.product_id == Product.id,
                            FeatureValue.feature_def_id == fid,
                            FeatureValue.value_text.isnot(None),
                            func.lower(func.trim(FeatureValue.value_text)) == selected_legacy_value.casefold(),
                        )
                    )
                )
            continue
        selected_option_id = _to_int(filter_row.get("value"), 0)
        if selected_option_id > 0:
            query = query.filter(_feature_text_option_filter_exists(fid, int(selected_option_id)))
    return query


def _mobile_catalog_filter_payload(feature_filters: list[dict[str, object]]) -> list[dict[str, object]]:
    payload: list[dict[str, object]] = []
    for row in feature_filters:
        payload.append(
            {
                "id": int(row.get("id") or 0),
                "label": str(row.get("label") or ""),
                "data_type": str(row.get("data_type") or "text"),
                "text_mode": str(row.get("text_mode") or "canonical"),
                "value": str(row.get("value") or ""),
                "min": str(row.get("min") or ""),
                "max": str(row.get("max") or ""),
                "options": row.get("options") or [],
                "min_options": row.get("min_options") or [],
                "max_options": row.get("max_options") or [],
                "bool_options": row.get("bool_options") or [],
            }
        )
    return payload


def _mobile_default_warehouse_id(db: Session) -> int:
    defaults = _receipt_defaults(db)
    warehouse_id = int(defaults.get("warehouse_id") or 0)
    if warehouse_id and db.get(Warehouse, warehouse_id):
        return warehouse_id
    first = db.query(Warehouse).order_by(Warehouse.name.asc(), Warehouse.id.asc()).first()
    return int(first.id) if first else 0


def _mobile_spare_default_owner_id(request: Request, owners: list[Owner]) -> int:
    by_id = {int(row.id): row for row in owners}
    raw_cookie = str(request.cookies.get(LAST_SPARE_OWNER_COOKIE) or "").strip()
    cookie_owner_id = _to_int(raw_cookie, 0)
    if cookie_owner_id > 0:
        owner = by_id.get(cookie_owner_id)
        if owner and bool(owner.active):
            return int(owner.id)
    if len(owners) == 1:
        return int(owners[0].id)
    return 0


def _mobile_spare_default_condition(db: Session) -> str:
    defaults = _receipt_defaults(db)
    condition = _condition_code_from_input(str(defaults.get("condition") or _default_condition_code()))
    if _condition_exists(db, condition, active_only=True):
        return condition
    fallback_defs = _get_condition_defs(db, active_only=True, include_fallback=True)
    if fallback_defs:
        return str(fallback_defs[0].code or _default_condition_code())
    return _default_condition_code()


def _mobile_first_other_warehouse_id(warehouses: list[Warehouse], from_warehouse_id: int) -> int:
    if not warehouses:
        return 0
    first_id = int(warehouses[0].id)
    for row in warehouses:
        row_id = int(row.id)
        if row_id != int(from_warehouse_id or 0):
            return row_id
    return first_id


def _mobile_cost_param_from_cents(cents: int | None) -> str:
    if cents is None:
        return ""
    value = int(cents)
    euro_value = float(value) / 100.0
    return f"{euro_value:.2f}".rstrip("0").rstrip(".")


def _delivery_scan_normalize_source(raw_source: str | None) -> str:
    value = str(raw_source or "").strip().lower()
    if value in DELIVERY_SCAN_SOURCES:
        return value
    return DELIVERY_SCAN_SOURCE_LIEFERSCHEIN


def _delivery_scan_source_label(source: str) -> str:
    normalized = _delivery_scan_normalize_source(source)
    if normalized == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD:
        return "Produktschild"
    return "Lieferschein"


def _delivery_scan_page_href(source: str) -> str:
    normalized = _delivery_scan_normalize_source(source)
    if normalized == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD:
        return "/m/lieferschein?scan_source=produktschild"
    return "/m/lieferschein"


def _delivery_scan_tesseract_available() -> bool:
    return bool(shutil.which("tesseract"))


def _delivery_scan_compact_token(raw: str | None) -> str:
    return "".join(ch for ch in str(raw or "").upper() if ch.isalnum())


def _delivery_scan_extract_text(filename: str, payload: bytes) -> str:
    if not payload:
        raise ValueError("Datei ist leer.")
    if len(payload) > DELIVERY_SCAN_MAX_BYTES:
        raise ValueError("Datei ist zu groß (max. 12 MB).")
    if not _delivery_scan_tesseract_available():
        raise ValueError("OCR ist nicht verfügbar. Bitte Tesseract installieren.")

    suffix = str(Path(filename or "").suffix or "").lower().strip()
    if suffix not in DELIVERY_SCAN_ALLOWED_SUFFIXES:
        raise ValueError("Nur Bilddateien (JPG/PNG/WEBP/BMP/TIFF) sind erlaubt.")

    dirs = ensure_dirs()
    scan_dir = dirs["tmp"] / "delivery_scan"
    scan_dir.mkdir(parents=True, exist_ok=True)
    tmp_file = tempfile.NamedTemporaryFile(
        dir=str(scan_dir),
        prefix="scan_",
        suffix=suffix,
        delete=False,
    )
    tmp_path = Path(tmp_file.name)
    try:
        tmp_file.write(payload)
        tmp_file.flush()
        tmp_file.close()

        text_parts: list[str] = []
        for psm in ("6", "11"):
            cmd = ["tesseract", str(tmp_path), "stdout", "-l", "deu+eng", "--psm", psm]
            run = subprocess.run(
                cmd,
                check=False,
                capture_output=True,
                text=True,
                timeout=35,
            )
            if run.returncode != 0:
                err = (run.stderr or "").strip() or "OCR fehlgeschlagen."
                raise ValueError(err)
            chunk = str(run.stdout or "").strip()
            if chunk and chunk not in text_parts:
                text_parts.append(chunk)
        text = "\n\n".join(text_parts).strip()
        if not text:
            raise ValueError("Kein lesbarer Text gefunden. Bitte klareres Foto aufnehmen.")
        return text
    finally:
        try:
            tmp_path.unlink(missing_ok=True)
        except Exception:
            pass


def _delivery_scan_extract_references(raw_text: str) -> list[str]:
    text = str(raw_text or "")
    out: list[str] = []

    def _append(value: str):
        token = str(value or "").strip().upper()
        if not token:
            return
        if len(token) < 3 or len(token) > 40:
            return
        if token not in out:
            out.append(token)

    for po in _extract_po_numbers(text):
        _append(po)

    pattern = re.compile(
        r"(?:kommission|auftrag|auftragsnr|auftragsnummer|ref|referenz|lieferschein|ls)\s*[:#-]?\s*([A-Za-z0-9][A-Za-z0-9\-/]{2,})",
        re.IGNORECASE,
    )
    for match in pattern.findall(text):
        _append(match)

    return out[:8]


def _delivery_scan_detect_mode(raw_text: str, has_reservation_hint: bool) -> str:
    text = _normalize_search_text(raw_text)
    if any(word in text for word in ("umlagerung", "umlagern", "transfer", "von lager", "nach lager")):
        return "transfer"
    if any(word in text for word in ("kommission", "kunde", "ausgang", "versand", "auslieferung", "warenausgang")):
        return "issue"
    if any(word in text for word in ("wareneingang", "lieferschein", "anlieferung", "lieferung", "eingang")):
        return "receipt"
    if has_reservation_hint:
        return "issue"
    return "receipt"


def _delivery_scan_guess_qty_from_line(line_text: str) -> int:
    text = str(line_text or "")
    patterns = [
        r"\b(?:menge|anzahl|qty)\s*[:=]?\s*(\d{1,4})\b",
        r"\b(\d{1,4})\s*(?:x|stk|st\.?|stueck|stück|pcs)\b",
        r"\b(\d{1,4})\b\s*$",
    ]
    for pattern in patterns:
        m = re.search(pattern, text, re.IGNORECASE)
        if not m:
            continue
        try:
            qty = int(m.group(1))
        except Exception:
            qty = 0
        if 0 < qty <= 1000:
            return qty
    return 1


def _delivery_scan_build_suggestions(
    db: Session,
    recognized_text: str,
    mode_hint: str,
    scan_source: str = DELIVERY_SCAN_SOURCE_LIEFERSCHEIN,
) -> dict[str, object]:
    source = _delivery_scan_normalize_source(scan_source)
    is_label_scan = source == DELIVERY_SCAN_SOURCE_PRODUKTSCHILD
    lines = [str(line).strip() for line in str(recognized_text or "").splitlines() if str(line).strip()]
    line_rows = [
        {
            "raw": line,
            "norm": _normalize_search_text(line),
            "compact": _delivery_scan_compact_token(line),
        }
        for line in lines
    ]
    doc_norm = _normalize_search_text(recognized_text)
    doc_compact = _delivery_scan_compact_token(recognized_text)
    reference_candidates = _delivery_scan_extract_references(recognized_text)

    products = (
        db.query(Product)
        .filter(Product.active == True)
        .order_by(Product.id.desc())
        .limit(5000)
        .all()
    )

    matched_rows: list[dict[str, object]] = []
    for product in products:
        best_score = 0
        best_line_idx = -1
        best_by = ""

        ean = str(product.ean or "").strip()
        if len(ean) >= 8:
            token = _delivery_scan_compact_token(ean)
            if token and token in doc_compact:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 180
                        best_line_idx = idx
                        best_by = "EAN"
                        break

        material_no = str(product.material_no or "").strip()
        if len(material_no) >= 4:
            token = _delivery_scan_compact_token(material_no)
            if token and token in doc_compact and best_score < 160:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 160
                        best_line_idx = idx
                        best_by = "Materialnummer"
                        break

        sku = str(product.sku or "").strip()
        if len(sku) >= 3:
            token = _delivery_scan_compact_token(sku)
            if token and token in doc_compact and best_score < 150:
                for idx, line_row in enumerate(line_rows):
                    if token in str(line_row["compact"]):
                        best_score = 150
                        best_line_idx = idx
                        best_by = "Artikelnummer"
                        break

        title_1 = _normalize_search_text(product.product_title_1 or "")
        title_1_min = 6 if is_label_scan else 10
        if len(title_1) >= title_1_min and title_1 in doc_norm and best_score < 100:
            for idx, line_row in enumerate(line_rows):
                if title_1 in str(line_row["norm"]):
                    best_score = 100
                    best_line_idx = idx
                    best_by = "Produkttitel 1"
                    break

        title_2 = _normalize_search_text(product.product_title_2 or "")
        title_2_min = 6 if is_label_scan else 10
        if len(title_2) >= title_2_min and title_2 in doc_norm and best_score < 97:
            for idx, line_row in enumerate(line_rows):
                if title_2 in str(line_row["norm"]):
                    best_score = 97
                    best_line_idx = idx
                    best_by = "Produkttitel 2"
                    break

        sales_name = _normalize_search_text(product.sales_name or "")
        sales_name_min = 6 if is_label_scan else 10
        if len(sales_name) >= sales_name_min and sales_name in doc_norm and best_score < 95:
            for idx, line_row in enumerate(line_rows):
                if sales_name in str(line_row["norm"]):
                    best_score = 95
                    best_line_idx = idx
                    best_by = "Verkaufsname"
                    break

        name = _normalize_search_text(product.name or "")
        needs_two_words = not is_label_scan
        if len(name) >= (6 if is_label_scan else 10) and (not needs_two_words or len(name.split()) >= 2) and name in doc_norm and best_score < 85:
            for idx, line_row in enumerate(line_rows):
                if name in str(line_row["norm"]):
                    best_score = 85
                    best_line_idx = idx
                    best_by = "Produktname"
                    break

        if best_score <= 0:
            continue
        line_text = ""
        if 0 <= best_line_idx < len(line_rows):
            line_text = str(line_rows[best_line_idx]["raw"])
        qty_guess = _delivery_scan_guess_qty_from_line(line_text)
        matched_rows.append(
            {
                "product": product,
                "score": best_score,
                "line_index": best_line_idx,
                "line_text": line_text,
                "qty_guess": qty_guess,
                "matched_by": best_by,
            }
        )

    matched_rows.sort(key=lambda row: (-int(row["score"]), int(row["line_index"] if int(row["line_index"]) >= 0 else 999999)))
    matched_rows = matched_rows[:40]
    if not matched_rows:
        return {
            "recognized_text": recognized_text,
            "mode": "receipt" if mode_hint == "auto" else mode_hint,
            "references": reference_candidates,
            "scan_source": source,
            "lines": [],
        }

    product_ids = [int(row["product"].id) for row in matched_rows]
    active_reservations = (
        db.query(Reservation)
        .filter(
            Reservation.status == "active",
            Reservation.product_id.in_(product_ids),
        )
        .order_by(Reservation.id.desc())
        .all()
    )
    reservations_by_product: dict[int, list[Reservation]] = {}
    for row in active_reservations:
        reservations_by_product.setdefault(int(row.product_id), []).append(row)

    has_reservation_hint = any(bool(rows) for rows in reservations_by_product.values())
    if mode_hint in ("receipt", "issue", "transfer"):
        detected_mode = mode_hint
    else:
        detected_mode = _delivery_scan_detect_mode(recognized_text, has_reservation_hint)

    receipt_defaults = _receipt_defaults(db)
    default_condition = str(receipt_defaults.get("condition") or _default_condition_code())
    default_to_warehouse_id = int(receipt_defaults.get("warehouse_id") or 0)
    if default_to_warehouse_id and not db.get(Warehouse, default_to_warehouse_id):
        default_to_warehouse_id = 0
    warehouses = db.query(Warehouse).order_by(Warehouse.name.asc(), Warehouse.id.asc()).all()
    if default_to_warehouse_id <= 0 and warehouses:
        default_to_warehouse_id = int(warehouses[0].id)
    default_from_warehouse_id = _mobile_default_warehouse_id(db)
    default_transfer_to = _mobile_first_other_warehouse_id(warehouses, default_from_warehouse_id)

    out_lines: list[dict[str, object]] = []
    seen_product_ids: set[int] = set()
    for idx, match_row in enumerate(matched_rows, start=1):
        product: Product = match_row["product"]
        product_id = int(product.id)
        if product_id in seen_product_ids:
            continue
        seen_product_ids.add(product_id)

        reservation_rows = reservations_by_product.get(product_id, [])
        matched_reservation: Reservation | None = None
        if reservation_rows:
            if reference_candidates:
                lowered_refs = [ref.casefold() for ref in reference_candidates]
                for res in reservation_rows:
                    ref_text = str(res.reference or "").strip().casefold()
                    if ref_text and any(ref in ref_text for ref in lowered_refs):
                        matched_reservation = res
                        break
            if matched_reservation is None and len(reservation_rows) == 1:
                matched_reservation = reservation_rows[0]

        qty = int(match_row["qty_guess"] or 1)
        if matched_reservation and int(matched_reservation.qty or 0) > 0:
            qty = int(matched_reservation.qty)
        qty = max(1, min(1000, int(qty)))

        tx_type = detected_mode
        if matched_reservation:
            tx_type = "issue"

        line_reference = ""
        if matched_reservation and str(matched_reservation.reference or "").strip():
            line_reference = str(matched_reservation.reference or "").strip()
        elif reference_candidates:
            line_reference = str(reference_candidates[0])

        warehouse_from_id = int(matched_reservation.warehouse_id) if matched_reservation else int(default_from_warehouse_id or 0)
        warehouse_to_id = int(default_to_warehouse_id or 0)
        if tx_type == "transfer":
            warehouse_from_id = int(default_from_warehouse_id or 0)
            warehouse_to_id = int(default_transfer_to or 0)
        if matched_reservation and tx_type == "issue":
            warehouse_to_id = 0
        if tx_type == "issue":
            warehouse_to_id = 0
        if tx_type == "receipt":
            warehouse_from_id = 0

        condition = str(matched_reservation.condition or default_condition) if matched_reservation else default_condition
        if not _condition_exists(db, condition, active_only=True):
            condition = default_condition

        out_lines.append(
            {
                "idx": idx,
                "product_id": product_id,
                "product_name": _mobile_display_name(product),
                "material_no": str(product.material_no or "").strip(),
                "matched_by": str(match_row["matched_by"] or ""),
                "line_text": str(match_row["line_text"] or ""),
                "score": int(match_row["score"] or 0),
                "qty": qty,
                "tx_type": tx_type,
                "warehouse_from_id": int(warehouse_from_id or 0),
                "warehouse_to_id": int(warehouse_to_id or 0),
                "condition": condition,
                "reference": line_reference,
                "reservation_id": int(matched_reservation.id) if matched_reservation else 0,
                "reservation_qty": int(matched_reservation.qty or 0) if matched_reservation else 0,
                "reservation_ref": str(matched_reservation.reference or "").strip() if matched_reservation else "",
            }
        )

    return {
        "recognized_text": recognized_text,
        "mode": detected_mode,
        "references": reference_candidates,
        "scan_source": source,
        "lines": out_lines,
    }


_po_re = re.compile(r"PO-\d{4}-\d{4}", re.IGNORECASE)


def _extract_po_numbers(text: str | None) -> list[str]:
    raw = str(text or "")
    found = _po_re.findall(raw)
    out: list[str] = []
    for f in found:
        key = str(f).upper()
        if key not in out:
            out.append(key)
    return out


def _seed_item_type_field_rules(db: Session) -> None:
    for item_type in ITEM_TYPE_CHOICES:
        defaults = DEFAULT_ITEM_TYPE_RULES.get(item_type, {})
        existing_rows = (
            db.query(ItemTypeFieldRule)
            .filter(ItemTypeFieldRule.item_type == item_type)
            .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
            .all()
        )
        existing_keys = {str(row.field_key) for row in existing_rows}
        max_sort_order = 0
        for row in existing_rows:
            try:
                max_sort_order = max(max_sort_order, int(row.sort_order or 0))
            except Exception:
                continue
        for idx, field in enumerate(FORM_FIELDS, start=1):
            key = str(field["key"])
            if key in existing_keys:
                continue
            cfg = defaults.get(key, {})
            max_sort_order += 10
            db.add(
                ItemTypeFieldRule(
                    item_type=item_type,
                    field_key=key,
                    visible=bool(cfg.get("visible", False)),
                    required=bool(cfg.get("required", False)),
                    sort_order=max_sort_order if max_sort_order > 0 else idx * 10,
                    section=str(field.get("section_default") or "Identifikation"),
                    help_text_de=None,
                )
            )


def _item_type_field_rules(db: Session, item_type: str) -> list[ItemTypeFieldRule]:
    normalized = _normalize_item_type(item_type, fallback="material")
    rows = (
        db.query(ItemTypeFieldRule)
        .filter(ItemTypeFieldRule.item_type == normalized)
        .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
        .all()
    )
    if rows:
        return rows
    _seed_item_type_field_rules(db)
    db.commit()
    return (
        db.query(ItemTypeFieldRule)
        .filter(ItemTypeFieldRule.item_type == normalized)
        .order_by(ItemTypeFieldRule.sort_order.asc(), ItemTypeFieldRule.id.asc())
        .all()
    )


def _product_form_schema(db: Session, item_type: str) -> list[dict]:
    rows = _item_type_field_rules(db, item_type)
    schema: list[dict] = []
    for row in rows:
        spec = FORM_FIELDS_BY_KEY.get(str(row.field_key))
        if not spec or not row.visible:
            continue
        schema.append(
            {
                "key": str(row.field_key),
                "label": str(spec["label_de"]),
                "input_type": str(spec["input_type"]),
                "placeholder": str(spec.get("placeholder_de") or ""),
                "required": bool(row.required),
                "section": str(row.section or spec.get("section_default") or "Identifikation"),
                "help_text": (row.help_text_de or "").strip(),
                "sort_order": int(row.sort_order or 0),
            }
        )
    schema.sort(key=lambda s: (str(s["section"]).lower(), int(s["sort_order"]), str(s["label"]).lower()))
    return schema


def _product_form_key_sets(db: Session, item_type: str) -> tuple[set[str], set[str]]:
    rows = _item_type_field_rules(db, item_type)
    visible = {str(r.field_key) for r in rows if r.visible}
    required = {str(r.field_key) for r in rows if r.visible and r.required}
    return visible, required


def _product_field_label(field_key: str) -> str:
    spec = FORM_FIELDS_BY_KEY.get(field_key)
    if spec:
        return str(spec["label_de"])
    return field_key


def _parse_product_select_id(db: Session, field_key: str, raw_value) -> tuple[int | None, bool]:
    try:
        value = int(raw_value or 0) or None
    except Exception:
        value = None
    if not value:
        return None, False
    model = None
    if field_key == "manufacturer_id":
        model = Manufacturer
    elif field_key == "area_id":
        model = Area
    elif field_key == "device_kind_id":
        model = DeviceKind
    elif field_key == "device_type_id":
        model = DeviceType
    if model is None:
        return value, True
    row = db.get(model, value)
    return value, bool(row)


def _parse_product_image_urls(form, add_error) -> dict[str, str | None]:
    out: dict[str, str | None] = {}
    for key in _product_image_url_keys():
        raw = (form.get(key) or "").strip()
        if not raw:
            out[key] = None
            continue
        normalized = _normalize_product_image_url(raw)
        if not normalized:
            add_error(key, f"Bild-Link in '{key}' muss mit http://, https:// oder /uploads/ beginnen.")
            out[key] = None
            continue
        out[key] = normalized
    return out


def _minimum_visible_fields(item_type: str) -> set[str]:
    normalized = _normalize_item_type(item_type, fallback="material")
    if normalized == "appliance":
        return {"sales_name", "material_no", "manufacturer_id", "device_kind_id"}
    if normalized == "spare_part":
        return {"name", "material_no"}
    if normalized == "accessory":
        return {"name", "material_no"}
    return {"name", "material_no"}


def _seed_defaults(db: Session):
    # instance
    inst = db.get(InstanceConfig, 1)
    if not inst:
        db.add(InstanceConfig(id=1, initialized_at=None))
    # setup state
    st = db.get(SetupState, 1)
    if not st:
        db.add(SetupState(id=1, current_step=0, completed_steps_json="[]"))
    # company profile row
    cp = db.get(CompanyProfile, 1)
    if not cp:
        db.add(CompanyProfile(id=1))
    # default service port info (does not change docker mapping, just documentation)
    if db.query(ServicePort).filter(ServicePort.service_name == "web").count() == 0:
        db.add(ServicePort(service_name="web", port=int(os.environ.get("APP_PORT", "8080")), protocol="http", exposed=True))
    # default storage paths
    defaults = {
        "data": str(DATA_DIR),
        "uploads": str(DATA_DIR / "uploads"),
        "backups": str(DATA_DIR / "backups"),
        "secrets": str(DATA_DIR / "secrets"),
    }
    for purpose, path in defaults.items():
        if db.query(StoragePath).filter(StoragePath.purpose == purpose).count() == 0:
            db.add(StoragePath(purpose=purpose, path=path))
    # default areas
    for name in ["Waschen", "Spülen", "Kälte", "Wärme"]:
        if db.query(Area).filter(func.lower(Area.name) == name.lower()).count() == 0:
            db.add(Area(name=name))
    # default stock conditions
    for code, label_de, sort_order, active in DEFAULT_STOCK_CONDITIONS:
        row = db.get(StockConditionDef, code)
        if not row:
            db.add(StockConditionDef(code=code, label_de=label_de, sort_order=sort_order, active=active))
    _seed_item_type_field_rules(db)
    _ensure_repair_warehouse(db)
    _ensure_scrap_warehouse(db)
    if _system_setting_get(db, REPAIR_AUTO_PAPERLESS, None) is None:
        _system_setting_set(db, REPAIR_AUTO_PAPERLESS, "0")
    if _system_setting_get(db, SPARE_AUTO_PAPERLESS, None) is None:
        _system_setting_set(db, SPARE_AUTO_PAPERLESS, "0")
    db.query(User).filter(User.role == "user").update({User.role: "lesen"})
    db.commit()


def _pick_default_enabled_account(db: Session) -> EmailAccount | None:
    return (
        db.query(EmailAccount)
        .filter(EmailAccount.enabled == True)
        .order_by(EmailAccount.is_default.desc(), EmailAccount.id.asc())
        .first()
    )


async def _email_sender_loop() -> None:
    while True:
        SessionLocal = get_sessionmaker()
        db = SessionLocal()
        try:
            result = send_outbox_once(db, batch_size=20)
            if result.get("processed", 0) > 0:
                db.commit()
        except Exception:
            db.rollback()
        finally:
            db.close()
        await asyncio.sleep(EMAIL_SENDER_INTERVAL)


async def _email_imap_loop() -> None:
    while True:
        SessionLocal = get_sessionmaker()
        db = SessionLocal()
        try:
            account = _pick_default_enabled_account(db)
            if account and account.imap_host and account.imap_port:
                fetch_inbox_once(db, account.id, limit=30)
            _repair_sync_inbound_mail(db, limit=30)
            db.commit()
        except Exception:
            db.rollback()
        finally:
            db.close()
        await asyncio.sleep(EMAIL_IMAP_INTERVAL)


async def _outsmart_sync_loop() -> None:
    while True:
        SessionLocal = get_sessionmaker()
        db = SessionLocal()
        try:
            if _customer_init_mode(db):
                db.rollback()
            else:
                _outsmart_delta_sync_once(db, limit=20)
                _outsmart_sync_completed_once(db, limit=20)
                db.commit()
        except Exception:
            db.rollback()
        finally:
            db.close()
        await asyncio.sleep(OUTSMART_SYNC_INTERVAL)


def _current_qty_for_min_scope(db: Session, product: Product, warehouse_id: int, bin_id: int | None) -> int:
    cond = _default_min_stock_condition(db)
    q = db.query(func.coalesce(func.sum(StockBalance.quantity), 0)).filter(
        StockBalance.product_id == product.id,
        StockBalance.warehouse_id == warehouse_id,
        StockBalance.condition == cond,
    )
    if bin_id is not None:
        q = q.filter(StockBalance.bin_id == bin_id)
    return int(q.scalar() or 0)


def _collect_min_stock_warnings(
    db: Session,
    warehouse_id: int | None = None,
    bin_id: int | None = None,
    limit: int = 200,
) -> list[dict]:
    q = db.query(MinStock).order_by(MinStock.id.asc())
    if warehouse_id:
        q = q.filter(MinStock.warehouse_id == warehouse_id)
    if bin_id is not None:
        q = q.filter(MinStock.bin_id == bin_id)
    rows = q.limit(limit).all()
    if not rows:
        return []
    products = {p.id: p for p in db.query(Product).all()}
    warehouses = {w.id: w for w in db.query(Warehouse).all()}
    bins = {b.id: b for b in db.query(WarehouseBin).all()}
    out: list[dict] = []
    for row in rows:
        product = products.get(row.product_id)
        if not product:
            continue
        current = _current_qty_for_min_scope(db, product, row.warehouse_id, row.bin_id)
        minimum = int(row.min_qty or 0)
        if current >= minimum:
            continue
        out.append(
            {
                "product_id": row.product_id,
                "product_name": product.name,
                "warehouse_id": row.warehouse_id,
                "warehouse_name": warehouses.get(row.warehouse_id).name if warehouses.get(row.warehouse_id) else str(row.warehouse_id),
                "bin_id": row.bin_id,
                "bin_name": bins.get(row.bin_id).code if row.bin_id and bins.get(row.bin_id) else "",
                "current_qty": current,
                "min_qty": minimum,
                "missing_qty": minimum - current,
            }
        )
    return out


ALLOWED_ROLES = ("admin", "lagerist", "techniker", "lesen")


@app.middleware("http")
async def setup_and_auth_gate(request: Request, call_next):
    # attach user + enforce first-run setup
    SessionLocal = get_sessionmaker()
    db = SessionLocal()
    try:
        request.state.user = get_current_user(request, db)
        if request.state.user is not None:
            now = dt.datetime.utcnow().replace(tzinfo=None)
            if "customer_view" not in request.session:
                request.session["customer_view"] = True
            if bool(request.session.get("customer_view", True)):
                request.session.pop("customer_view_until", None)
            else:
                until_raw = (request.session.get("customer_view_until") or "").strip()
                until_dt = None
                if until_raw:
                    try:
                        until_dt = dt.datetime.fromisoformat(until_raw)
                    except Exception:
                        until_dt = None
                if until_dt is None:
                    until_dt = now + dt.timedelta(seconds=CUSTOMER_VIEW_TIMEOUT_SECONDS)
                    request.session["customer_view_until"] = until_dt.isoformat()
                elif now >= until_dt:
                    request.session["customer_view"] = True
                    request.session.pop("customer_view_until", None)
        else:
            request.session.pop("customer_view", None)
            request.session.pop("customer_view_until", None)

        path = request.url.path
        allow_setup_paths = (
            path.startswith("/setup")
            or path.startswith("/static")
            or path.startswith("/meta")
            or path.startswith("/health")
        )

        if not is_initialized(db) and not allow_setup_paths:
            return RedirectResponse(url="/setup", status_code=302)

        # If initialized: keep /setup reachable (admin can use it later). We do not hard-block here.
    finally:
        db.close()

    response = await call_next(request)
    return response


# IMPORTANT: SessionMiddleware must run *before* our custom middleware accesses request.session.
# Starlette/FastAPI middleware ordering means the last added middleware runs first (outermost).
# Therefore we add SessionMiddleware *after* defining @app.middleware handlers.
app.add_middleware(SessionMiddleware, secret_key=get_session_secret(), max_age=60 * 60 * 24 * 7)


@app.exception_handler(HTTPException)
@app.exception_handler(StarletteHTTPException)
async def http_exception_redirect_handler(request: Request, exc: HTTPException | StarletteHTTPException):
    status_code = int(getattr(exc, "status_code", 500))
    detail = getattr(exc, "detail", "Fehler")
    headers = getattr(exc, "headers", None) or {}

    if not _wants_json(request):
        accept = (request.headers.get("accept") or "").lower()
        wants_html = "text/html" in accept or accept == "" or "*/*" in accept
        if wants_html and not request.url.path.startswith("/api"):
            if status_code == 401:
                try:
                    _flash(request, "Bitte anmelden.", "warn")
                except Exception:
                    pass
                return RedirectResponse("/login", status_code=302)
            if status_code == 403:
                return templates.TemplateResponse(
                    "error.html",
                    _ctx(
                        request,
                        title="Zugriff verweigert",
                        error_title="Zugriff verweigert",
                        error_message="Für diese Seite fehlen die erforderlichen Rechte.",
                        error_code=403,
                    ),
                    status_code=403,
                )
            if status_code == 404:
                return templates.TemplateResponse(
                    "error.html",
                    _ctx(
                        request,
                        title="Seite nicht gefunden",
                        error_title="Seite nicht gefunden",
                        error_message="Die angeforderte Seite wurde nicht gefunden.",
                        error_code=404,
                    ),
                    status_code=404,
                )

    return JSONResponse(status_code=status_code, content={"detail": detail}, headers=headers)


