@app.get("/crm/kunden/{customer_id}/zusammenfuehren", response_class=HTMLResponse)
def crm_customer_merge_get(
    customer_id: int,
    request: Request,
    user=Depends(require_admin),
    q: str = "",
    target_id: int = 0,
    db: Session = Depends(db_session),
):
    source_customer = db.get(MasterCustomer, customer_id)
    if not source_customer:
        raise HTTPException(status_code=404)
    source_party = db.get(Party, int(source_customer.party_id))
    if not source_party:
        raise HTTPException(status_code=404)
    _, source_default_map = _crm_party_address_maps(db, [int(source_party.id)])
    source_default_address = source_default_map.get(int(source_party.id))

    selected_target = db.get(MasterCustomer, int(target_id)) if int(target_id or 0) > 0 else None
    if selected_target and int(selected_target.id) == int(source_customer.id):
        selected_target = None
    search_text = str(q or "").strip()
    rows: list[MasterCustomer] = []
    if search_text:
        like = f"%{search_text}%"
        rows = (
            db.query(MasterCustomer)
            .join(Party, Party.id == MasterCustomer.party_id)
            .filter(
                MasterCustomer.id != int(source_customer.id),
                or_(
                    MasterCustomer.customer_no_internal.ilike(like),
                    Party.display_name.ilike(like),
                    Party.first_name.ilike(like),
                    Party.last_name.ilike(like),
                    MasterCustomer.note.ilike(like),
                ),
            )
            .order_by(MasterCustomer.status.asc(), Party.display_name.asc(), MasterCustomer.id.asc())
            .limit(40)
            .all()
        )
    elif selected_target:
        rows = [selected_target]
    party_ids = [int(row.party_id) for row in rows]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    search_rows = [
        {
            "customer": row,
            "party": parties.get(int(row.party_id)),
            "default_address": default_map.get(int(row.party_id)),
            "label": _crm_customer_label(row, parties.get(int(row.party_id)), default_map.get(int(row.party_id))),
        }
        for row in rows
    ]
    preview = None
    preview_target_party = None
    preview_target_address = None
    if selected_target:
        preview = build_customer_merge_preview(db, source_customer=source_customer, target_customer=selected_target)
        preview_target_party = db.get(Party, int(selected_target.party_id))
        _, preview_map = _crm_party_address_maps(db, [int(selected_target.party_id)])
        preview_target_address = preview_map.get(int(selected_target.party_id))
    return templates.TemplateResponse(
        "crm/customer_merge_form.html",
        _ctx(
            request,
            user=user,
            source_customer=source_customer,
            source_party=source_party,
            source_default_address=source_default_address,
            q=search_text,
            search_rows=search_rows,
            selected_target=selected_target,
            preview=preview,
            preview_target_party=preview_target_party,
            preview_target_address=preview_target_address,
        ),
    )


@app.post("/crm/kunden/{customer_id}/zusammenfuehren")
async def crm_customer_merge_post(customer_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    source_customer = db.get(MasterCustomer, customer_id)
    if not source_customer:
        raise HTTPException(status_code=404)
    form = await request.form()
    target_id = _to_int(form.get("target_customer_id"), 0)
    if target_id <= 0 or int(target_id) == int(source_customer.id):
        _flash(request, "Bitte einen anderen Zielkunden wählen.", "error")
        return RedirectResponse(f"/crm/kunden/{customer_id}/zusammenfuehren", status_code=302)
    target_customer = db.get(MasterCustomer, target_id)
    if not target_customer:
        _flash(request, "Zielkunde wurde nicht gefunden.", "error")
        return RedirectResponse(f"/crm/kunden/{customer_id}/zusammenfuehren", status_code=302)
    actor_label = str(getattr(user, "full_name", "") or getattr(user, "username", "") or getattr(user, "email", "") or f"User #{int(user.id)}").strip()
    try:
        summary = merge_master_customers(
            db,
            target_customer=target_customer,
            source_customer=source_customer,
            actor_label=actor_label,
        )
        rejections = _crm_merge_rejections(db)
        rejections.discard(_crm_merge_pair_key(int(target_customer.id), int(source_customer.id)))
        _crm_save_merge_rejections(db, rejections)
        db.commit()
    except CustomerMergeConflict as exc:
        db.rollback()
        _flash(request, str(exc), "error")
        return RedirectResponse(
            f"/crm/kunden/{customer_id}/zusammenfuehren?target_id={int(target_customer.id)}",
            status_code=302,
        )
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return RedirectResponse(
            f"/crm/kunden/{customer_id}/zusammenfuehren?target_id={int(target_customer.id)}",
            status_code=302,
        )
    moved_bits = [
        f"Adressen: {summary.get('addresses', 0)}",
        f"Kontakte: {summary.get('contacts', 0)}",
        f"Standorte: {summary.get('locations', 0)}",
        f"Objekte: {summary.get('objects', 0)}",
        f"Mails: {summary.get('mail_threads', 0) + summary.get('mail_messages', 0) + summary.get('mail_outbox', 0)}",
        f"Identitäten: {summary.get('external_identities', 0)}",
    ]
    _flash(
        request,
        f"{source_customer.customer_no_internal} wurde in {target_customer.customer_no_internal} zusammengeführt. {' | '.join(moved_bits)}.",
        "info",
    )
    return RedirectResponse(f"/crm/kunden/{int(target_customer.id)}", status_code=302)


@app.post("/crm/kunden/{customer_id}/outsmart/synchronisieren")
def crm_customer_outsmart_sync(customer_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    settings = _outsmart_settings(db, include_secret=True)
    if not bool(settings.get("enabled")):
        _flash(request, "OutSmart ist deaktiviert.", "error")
        return RedirectResponse(f"/crm/kunden/{customer_id}", status_code=302)
    if not bool(settings.get("token")) or not bool(settings.get("software_token")):
        _flash(request, "Bitte zuerst die OutSmart-Zugangsdaten vervollständigen.", "error")
        return RedirectResponse(f"/crm/kunden/{customer_id}", status_code=302)
    _, default_map = _crm_party_address_maps(db, [int(party.id)])
    address = default_map.get(int(party.id))
    payload_row = _outsmart_relation_payload_for_customer(db, customer, party, address)
    job = _start_sync_job(db, system_name="outsmart", direction="push", entity_type="relation", log_text=f"Kunde {customer.customer_no_internal}")
    try:
        result = outsmart_push_relation(settings, payload_row)
        result_payload = _outsmart_first_row(result) or {}
        row_id = _outsmart_row_id(result_payload) or outsmart_first_value(result, ("RowId", "row_id", "id"))
        deep_link = _outsmart_pick_url(result_payload, ("DeepLinkUrl", "deep_link_url", "Url", "url")) or outsmart_build_deep_link(
            _outsmart_settings(db, include_secret=False),
            entity_type="relation",
            row_id=row_id or None,
            external_key=str(payload_row.get("RelationNo") or customer.customer_no_internal),
        )
        _upsert_external_link(
            db,
            system_name="outsmart",
            object_type="master_customer",
            object_id=int(customer.id),
            external_key=str(payload_row.get("RelationNo") or customer.customer_no_internal),
            external_row_id=row_id or None,
            deep_link_url=deep_link or None,
        )
        _crm_add_timeline_event(
            db,
            master_customer_id=int(customer.id),
            source_system="outsmart",
            event_type="relation_push",
            title="Kunde nach OutSmart synchronisiert",
            body=f"Relation: {payload_row.get('RelationNo') or customer.customer_no_internal}",
            event_ts=_utcnow_naive(),
            external_ref=row_id or str(payload_row.get("RelationNo") or customer.customer_no_internal),
            meta={"deep_link_url": deep_link or "", "relation_no": payload_row.get("RelationNo")},
        )
        _finish_sync_job(db, job, status="done", log_text=f"Relation exportiert: {payload_row.get('RelationNo')} ({row_id or '-'})")
        db.commit()
        _flash(request, "Kunde nach OutSmart synchronisiert.", "info")
    except Exception as exc:
        db.rollback()
        _flash(request, f"OutSmart-Synchronisierung fehlgeschlagen: {exc}", "error")
    return RedirectResponse(f"/crm/kunden/{customer_id}", status_code=302)


@app.get("/crm/kunden/{customer_id}/objekte", response_class=HTMLResponse)
def crm_customer_objects(customer_id: int, request: Request, user=Depends(require_user), object_id: int = 0, db: Session = Depends(db_session)):
    customer = db.get(MasterCustomer, customer_id)
    if not customer:
        raise HTTPException(status_code=404)
    party = db.get(Party, int(customer.party_id))
    if not party:
        raise HTTPException(status_code=404)
    rows = _customer_objects_for_customer(db, int(customer.id), limit=120)
    selected = None
    if int(object_id or 0) > 0:
        for item in rows:
            if int(item.id) == int(object_id):
                selected = item
                break
    if selected is None and rows:
        selected = rows[0]
    selected_workorders: list[OutsmartWorkorder] = []
    object_parts: list[dict | str] = []
    freefields: dict[str, object] = {}
    if selected:
        selected_workorders = (
            db.query(OutsmartWorkorder)
            .filter(OutsmartWorkorder.customer_object_id == int(selected.id))
            .order_by(OutsmartWorkorder.updated_at.desc(), OutsmartWorkorder.id.desc())
            .limit(25)
            .all()
        )
        object_parts = _outsmart_list_json(selected.object_parts_json)
        try:
            loaded = json.loads(selected.freefields_json or "{}")
            if isinstance(loaded, dict):
                freefields = loaded
        except Exception:
            freefields = {}
    return templates.TemplateResponse(
        "crm/customer_objects.html",
        _ctx(
            request,
            user=user,
            customer=customer,
            party=party,
            rows=rows,
            selected=selected,
            selected_workorders=selected_workorders,
            object_parts=object_parts,
            freefields=freefields,
        ),
    )


