def crm_identity_map(
    request: Request,
    user=Depends(require_user),
    q: str = "",
    system: str = "",
    db: Session = Depends(db_session),
):
    system_norm = _crm_normalize_key(system)
    query = db.query(ExternalIdentity)
    if system_norm in CRM_EXTERNAL_SYSTEM_CHOICES:
        query = query.filter(ExternalIdentity.system_name == system_norm)
    q_norm = _crm_normalize_key(q)
    if q_norm:
        like = f"%{_crm_clean_text(q)}%"
        query = query.filter(
            or_(
                ExternalIdentity.external_key.ilike(like),
                ExternalIdentity.external_id.ilike(like),
                ExternalIdentity.note.ilike(like),
            )
        )
    identities = query.order_by(ExternalIdentity.master_customer_id.asc(), ExternalIdentity.system_name.asc(), ExternalIdentity.id.asc()).all()
    customer_ids = [int(row.master_customer_id) for row in identities]
    customers = {int(row.id): row for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_(sorted(set(customer_ids)))).all()} if customer_ids else {}
    party_ids = [int(row.party_id) for row in customers.values()]
    parties = {int(row.id): row for row in db.query(Party).filter(Party.id.in_(party_ids)).all()} if party_ids else {}
    _, default_map = _crm_party_address_maps(db, party_ids)
    grouped: dict[int, dict[str, object]] = {}
    for identity in identities:
        customer = customers.get(int(identity.master_customer_id))
        if not customer:
            continue
        party = parties.get(int(customer.party_id))
        search_blob = " ".join(
            [
                str(customer.customer_no_internal or ""),
                str(party.display_name if party else ""),
                str(identity.external_key or ""),
                str(identity.external_id or ""),
            ]
        )
        if q_norm and q_norm not in _crm_normalize_key(search_blob):
            continue
        payload = grouped.setdefault(
            int(customer.id),
            {
                "customer": customer,
                "party": party,
                "default_address": default_map.get(int(customer.party_id)),
                "identities": [],
            },
        )
        payload["identities"].append(identity)
    return templates.TemplateResponse(
        "crm/customer_identity_map.html",
        _ctx(
            request,
            user=user,
            rows=list(grouped.values()),
            q=_crm_clean_text(q),
            system=system_norm,
            system_choices=CRM_EXTERNAL_SYSTEM_CHOICES,
            sevdesk_enabled=bool(_sevdesk_settings(db, include_secret=False).get("enabled")),
        ),
    )


@app.get("/crm/merge-kandidaten", response_class=HTMLResponse)
def crm_merge_candidates(request: Request, user=Depends(require_admin), q: str = "", ai: int = 0, db: Session = Depends(db_session)):
    rows = _crm_build_merge_candidates(db, q=q)
    ai_results: dict[str, dict[str, object]] = {}
    if bool(ai):
        for item in rows[:20]:
            master_address = item.get("master_address")
            candidate_address = item.get("candidate_address")
            sevdesk_identities = item.get("sevdesk_identities") or []
            ai_result = ai_evaluate_merge_candidate(
                db,
                settings=_openai_settings(db, include_secret=True),
                input_payload={
                    "master_id": int(item["master_customer"].id),
                    "candidate_id": int(item["candidate_customer"].id),
                    "master_name": str(item["master_party"].display_name or ""),
                    "candidate_name": str(item["candidate_party"].display_name or ""),
                    "master_email": str(getattr(master_address, "email", "") or ""),
                    "candidate_email": str(getattr(candidate_address, "email", "") or ""),
                    "master_phone": str(getattr(master_address, "phone", "") or ""),
                    "candidate_phone": str(getattr(candidate_address, "phone", "") or ""),
                    "master_zip": str(getattr(master_address, "zip_code", "") or ""),
                    "candidate_zip": str(getattr(candidate_address, "zip_code", "") or ""),
                    "master_outsmart_key": "",
                    "candidate_outsmart_key": str(sevdesk_identities[0].external_key if sevdesk_identities else ""),
                },
                related_object_id=int(item["master_customer"].id),
            )
            ai_results[_crm_merge_pair_key(int(item["master_customer"].id), int(item["candidate_customer"].id))] = ai_result
    return templates.TemplateResponse(
        "crm/customer_merge_candidates.html",
        _ctx(request, user=user, rows=rows, ai_results=ai_results, ai_enabled=bool(ai)),
    )


@app.post("/crm/merge-kandidaten/auto")
async def crm_merge_candidates_auto(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    q = _crm_clean_text(form.get("q"))
    try:
        summary = _crm_auto_merge_candidates(db, q=q)
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, f"Auto-Merge fehlgeschlagen: {exc}", "error")
        return RedirectResponse("/crm/merge-kandidaten", status_code=302)
    _flash(
        request,
        f"Auto-Merge abgeschlossen: {summary.get('merged', 0)} zusammengeführt | {summary.get('manual', 0)} bleiben zur Prüfung | {summary.get('errors', 0)} Fehler.",
        "info",
    )
    return RedirectResponse("/crm/merge-kandidaten", status_code=302)


@app.post("/crm/merge-kandidaten/{master_id}/zuordnen")
async def crm_merge_candidate_assign(master_id: int, request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    candidate_id = _to_int(form.get("candidate_id"), 0)
    master = db.get(MasterCustomer, master_id)
    candidate = db.get(MasterCustomer, candidate_id)
    if not master or not candidate:
        raise HTTPException(status_code=404)
    candidate_identities = db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id == int(candidate.id)).all()
    master_identities = db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id == int(master.id)).all()
    candidate_outsmart = {
        _crm_normalize_key(identity.external_key or identity.external_id)
        for identity in candidate_identities
        if _crm_normalize_key(identity.system_name) == "outsmart" and _crm_normalize_key(identity.external_key or identity.external_id)
    }
    master_outsmart = {
        _crm_normalize_key(identity.external_key or identity.external_id)
        for identity in master_identities
        if _crm_normalize_key(identity.system_name) == "outsmart" and _crm_normalize_key(identity.external_key or identity.external_id)
    }
    if candidate_outsmart and candidate_outsmart != master_outsmart:
        _flash(request, "Der Kandidat hat eine eigene OutSmart-Identität. OutSmart ist führend und darf nicht blind umgehängt werden.", "error")
        return RedirectResponse("/crm/merge-kandidaten", status_code=302)
    sevdesk_rows = [identity for identity in candidate_identities if _crm_normalize_key(identity.system_name) == "sevdesk"]
    if not sevdesk_rows:
        _flash(request, "Beim Kandidaten wurden keine sevDesk-Identitäten gefunden.", "info")
        return RedirectResponse("/crm/merge-kandidaten", status_code=302)
    master_has_primary = any(_crm_normalize_key(identity.system_name) == "sevdesk" and bool(identity.is_primary) for identity in master_identities)
    for idx, identity in enumerate(sevdesk_rows):
        identity.master_customer_id = int(master.id)
        if master_has_primary:
            identity.is_primary = False
        elif idx == 0:
            identity.is_primary = True
            master_has_primary = True
        db.add(identity)
    try:
        db.commit()
    except Exception as exc:
        db.rollback()
        _flash(request, _friendly_db_write_error(exc), "error")
        return RedirectResponse("/crm/merge-kandidaten", status_code=302)
    _flash(request, f"{len(sevdesk_rows)} sevDesk-Identität(en) wurden dem Masterkunden zugeordnet.", "info")
    return RedirectResponse("/crm/merge-kandidaten", status_code=302)


@app.post("/crm/merge-kandidaten/ablehnen")
async def crm_merge_candidate_reject(request: Request, user=Depends(require_admin), db: Session = Depends(db_session)):
    form = await request.form()
    master_id = _to_int(form.get("master_id"), 0)
    candidate_id = _to_int(form.get("candidate_id"), 0)
    if master_id <= 0 or candidate_id <= 0:
        raise HTTPException(status_code=400)
    values = _crm_merge_rejections(db)
    values.add(_crm_merge_pair_key(master_id, candidate_id))
    _crm_save_merge_rejections(db, values)
    db.commit()
    _flash(request, "Merge-Kandidat abgelehnt.", "info")
    return RedirectResponse("/crm/merge-kandidaten", status_code=302)


def _customer_init_stage_counts(db: Session) -> dict[str, int]:
    return {
        "outsmart_relations": int(db.query(OutsmartRelationStage).count()),
        "outsmart_projects": int(db.query(OutsmartProjectStage).count()),
        "outsmart_workorders": int(db.query(OutsmartWorkorderStage).count()),
        "sevdesk_contacts": int(db.query(SevdeskContactStage).count()),
        "sevdesk_orders": int(db.query(SevdeskOrderStage).count()),
        "sevdesk_invoices": int(db.query(SevdeskInvoiceStage).count()),
    }


def _customer_init_cluster_counts(db: Session) -> dict[str, int]:
    counts = {key: 0 for key in CUSTOMER_INIT_CLUSTER_STATUS_CHOICES}
    rows = (
        db.query(CustomerInitCluster.status, func.count(CustomerInitCluster.id))
        .group_by(CustomerInitCluster.status)
        .all()
    )
    for status, amount in rows:
        key = _crm_normalize_key(status)
        if key in counts:
            counts[key] = int(amount or 0)
    counts["open"] = counts.get("ready", 0) + counts.get("needs_review", 0)
    return counts


def _customer_init_parse_datetime(raw: str | None) -> dt.datetime | None:
    return _outsmart_parse_datetime(raw)


def _customer_init_amount_cents(payload: dict) -> int | None:
    for key in ("sumGross", "gross", "amount", "total", "sum", "debit"):
        raw = str(payload.get(key) or "").strip()
        if not raw:
            continue
        if "," in raw:
            text = raw.replace(".", "").replace(",", ".")
        else:
            text = raw
        try:
            return int(round(float(text) * 100))
        except Exception:
            continue
    return None


def _customer_init_upsert_outsmart_relation_stage(db: Session, payload: dict) -> str:
    relation_no = _outsmart_pick(payload, ("RelationNo", "relation_no", "DebtorNo", "debtor_no"))
    if not relation_no:
        return "skipped"
    row = db.query(OutsmartRelationStage).filter(OutsmartRelationStage.relation_no == relation_no).one_or_none()
    created = row is None
    if row is None:
        row = OutsmartRelationStage(relation_no=relation_no, created_at=_utcnow_naive())
    street = _outsmart_pick(payload, ("Street", "street", "Address", "address"))
    email = _outsmart_pick(payload, ("Email", "email", "Mail", "mail"))
    phone = _outsmart_pick(payload, ("Phone", "phone", "PhoneNumber", "phone_number"))
    debtor_no = _outsmart_pick(payload, ("DebtorNo", "debtor_no", "RelationNo", "relation_no"))
    normalized = stage_normalized_fields(
        name=_outsmart_pick(payload, ("Name", "name")),
        street=street,
        zip_code=_outsmart_pick(payload, ("ZipCode", "zip_code", "PostalCode", "postal_code")),
        city=_outsmart_pick(payload, ("City", "city")),
        email=email,
        phone=phone,
        debtor=debtor_no,
        customer_number=relation_no,
    )
    values = {
        "debtor_no": debtor_no or None,
        "external_row_id": _outsmart_row_id(payload) or None,
        "name": _outsmart_pick(payload, ("Name", "name")) or None,
        "contact": _outsmart_pick(payload, ("Contact", "contact", "ContactName", "contact_name")) or None,
        "phone": phone or None,
        "email": email or None,
        "street": street or None,
        "house_no": _outsmart_pick(payload, ("HouseNo", "house_no", "StreetNo", "street_no")) or None,
        "zip_code": _outsmart_pick(payload, ("ZipCode", "zip_code", "PostalCode", "postal_code")) or None,
        "city": _outsmart_pick(payload, ("City", "city")) or None,
        "remark": _outsmart_pick(payload, ("Remark", "remark", "Description", "description")) or None,
        "latitude": float(_outsmart_pick(payload, ("Latitude", "latitude")) or 0) if _outsmart_pick(payload, ("Latitude", "latitude")) else None,
        "longitude": float(_outsmart_pick(payload, ("Longitude", "longitude")) or 0) if _outsmart_pick(payload, ("Longitude", "longitude")) else None,
        "raw_json": json.dumps(payload, ensure_ascii=False),
        "imported_at": _utcnow_naive(),
        "updated_at": _utcnow_naive(),
    }
    values.update(normalized)
    changed = created
    for key, value in values.items():
        if getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    db.add(row)
    db.flush()
    return "created" if created else "updated" if changed else "skipped"


def _customer_init_seed_outsmart_relation(
    db: Session,
    *,
    debtor_no: str,
    name: str = "",
    street: str = "",
    house_no: str = "",
    zip_code: str = "",
    city: str = "",
    remark: str = "",
) -> str:
    debtor_clean = _crm_clean_text(debtor_no)
    if not debtor_clean:
        return "skipped"
    payload = {
        "RelationNo": debtor_clean,
        "DebtorNo": debtor_clean,
        "Name": _crm_clean_text(name) or debtor_clean,
        "Street": _crm_clean_text(street),
        "HouseNo": _crm_clean_text(house_no),
        "ZipCode": _crm_clean_text(zip_code),
        "City": _crm_clean_text(city),
        "Remark": _crm_clean_text(remark),
    }
    return _customer_init_upsert_outsmart_relation_stage(db, payload)


def _customer_init_seed_outsmart_project(
    db: Session,
    *,
    project_code: str,
    debtor_number: str = "",
    debtor_number_invoice: str = "",
    name: str = "",
    status: str = "",
    remark: str = "",
) -> str:
    project_clean = _crm_clean_text(project_code)
    if not project_clean:
        return "skipped"
    payload = {
        "ProjectNo": project_clean,
        "RelationNo": _crm_clean_text(debtor_number),
        "RelationNoInvoice": _crm_clean_text(debtor_number_invoice),
        "ProjectName": _crm_clean_text(name) or project_clean,
        "Status": _crm_clean_text(status),
        "Description": _crm_clean_text(remark),
    }
    return _customer_init_upsert_outsmart_project_stage(db, payload)


def _customer_init_upsert_outsmart_project_stage(db: Session, payload: dict) -> str:
    project_code = _outsmart_project_key(payload)
    if not project_code:
        return "skipped"
    row = db.query(OutsmartProjectStage).filter(OutsmartProjectStage.project_code == project_code).one_or_none()
    created = row is None
    if row is None:
        row = OutsmartProjectStage(project_code=project_code, created_at=_utcnow_naive())
    debtor_number = _outsmart_customer_debtor_key(payload)
    debtor_number_invoice = _outsmart_invoice_debtor_key(payload)
    normalized = stage_normalized_fields(
        name=_outsmart_pick(payload, ("ProjectName", "project_name", "Name", "name")),
        debtor=debtor_number,
        customer_number=debtor_number_invoice or debtor_number,
    )
    values = {
        "external_row_id": _outsmart_row_id(payload) or None,
        "debtor_number": debtor_number or None,
        "debtor_number_invoice": debtor_number_invoice or None,
        "name": _outsmart_pick(payload, ("ProjectName", "project_name", "Name", "name")) or None,
        "status": _outsmart_pick(payload, ("Status", "status")) or None,
        "start_date": _customer_init_parse_datetime(_outsmart_pick(payload, ("DateStart", "date_start", "StartDate", "start_date"))),
        "end_date": _customer_init_parse_datetime(_outsmart_pick(payload, ("DateEnd", "date_end", "EndDate", "end_date"))),
        "raw_json": json.dumps(payload, ensure_ascii=False),
        "imported_at": _utcnow_naive(),
        "updated_at": _utcnow_naive(),
    }
    values.update(normalized)
    changed = created
    for key, value in values.items():
        if getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    db.add(row)
    db.flush()
    if debtor_number:
        _customer_init_seed_outsmart_relation(
            db,
            debtor_no=debtor_number,
            name=_outsmart_pick(payload, ("ProjectName", "project_name", "Name", "name")),
            remark="Synthetisch aus OutSmart-Projekt",
        )
    if debtor_number_invoice and debtor_number_invoice != debtor_number:
        _customer_init_seed_outsmart_relation(
            db,
            debtor_no=debtor_number_invoice,
            name=_outsmart_pick(payload, ("ProjectName", "project_name", "Name", "name")),
            remark="Synthetisch aus OutSmart-Projekt (Rechnungskunde)",
        )
    return "created" if created else "updated" if changed else "skipped"


def _customer_init_upsert_outsmart_workorder_stage(db: Session, payload: dict) -> str:
    workorder_no = _outsmart_workorder_key(payload)
    if not workorder_no:
        return "skipped"
    row = db.query(OutsmartWorkorderStage).filter(OutsmartWorkorderStage.workorder_no == workorder_no).one_or_none()
    created = row is None
    if row is None:
        row = OutsmartWorkorderStage(workorder_no=workorder_no, created_at=_utcnow_naive())
    customer_debtor = _outsmart_customer_debtor_key(payload)
    invoice_debtor = _outsmart_invoice_debtor_key(payload)
    normalized = stage_normalized_fields(
        name=_outsmart_pick(payload, ("CustomerName", "customer_name")),
        street=_outsmart_pick(payload, ("CustomerStreet", "customer_street")),
        zip_code=_outsmart_pick(payload, ("CustomerZIP", "CustomerZipCode", "customer_zip")),
        city=_outsmart_pick(payload, ("CustomerCity", "customer_city")),
        debtor=customer_debtor,
        customer_number=invoice_debtor or customer_debtor,
    )
    values = {
        "external_row_id": _outsmart_row_id(payload) or None,
        "customer_debtor_number": customer_debtor or None,
        "customer_invoice_debtor_number": invoice_debtor or None,
        "customer_name": _outsmart_pick(payload, ("CustomerName", "customer_name")) or None,
        "customer_name_invoice": _outsmart_pick(payload, ("CustomerNameInvoice", "customer_name_invoice", "CustomerInvoice")) or None,
        "project_code": _outsmart_pick(payload, ("ProjectNr", "project_nr", "ProjectNo")) or None,
        "external_project_code": _outsmart_pick(payload, ("ExternProjectNr", "extern_project_nr")) or None,
        "street": _outsmart_pick(payload, ("CustomerStreet", "customer_street")) or None,
        "house_no": _outsmart_pick(payload, ("CustomerStreetNo", "CustomerHouseNo", "customer_house_no")) or None,
        "zip_code": _outsmart_pick(payload, ("CustomerZIP", "CustomerZipCode", "customer_zip")) or None,
        "city": _outsmart_pick(payload, ("CustomerCity", "customer_city")) or None,
        "street_invoice": _outsmart_pick(payload, ("CustomerStreetInvoice", "CustomerInvoiceStreet")) or None,
        "house_no_invoice": _outsmart_pick(payload, ("CustomerStreetNoInvoice", "CustomerInvoiceHouseNo")) or None,
        "zip_code_invoice": _outsmart_pick(payload, ("CustomerZIPInvoice", "CustomerInvoiceZipCode")) or None,
        "city_invoice": _outsmart_pick(payload, ("CustomerCityInvoice", "CustomerInvoiceCity")) or None,
        "status": _outsmart_pick(payload, ("Status", "status")) or None,
        "raw_json": json.dumps(payload, ensure_ascii=False),
        "imported_at": _utcnow_naive(),
        "updated_at": _utcnow_naive(),
    }
    values.update(normalized)
    changed = created
    for key, value in values.items():
        if getattr(row, key) != value:
            setattr(row, key, value)
            changed = True
    db.add(row)
    db.flush()
    project_key = _outsmart_pick(payload, ("ProjectNr", "project_nr", "ProjectNo")) or _outsmart_pick(payload, ("ExternProjectNr", "extern_project_nr"))
    if project_key:
        _customer_init_seed_outsmart_project(
            db,
            project_code=project_key,
            debtor_number=customer_debtor,
            debtor_number_invoice=invoice_debtor,
            name=_outsmart_pick(payload, ("CustomerName", "customer_name")) or _outsmart_pick(payload, ("ShortWorkDescription", "short_work_description")),
            status=_outsmart_pick(payload, ("Status", "status")),
            remark="Synthetisch aus OutSmart-Arbeitsauftrag",
        )
    if customer_debtor:
        _customer_init_seed_outsmart_relation(
            db,
            debtor_no=customer_debtor,
            name=_outsmart_pick(payload, ("CustomerName", "customer_name")),
            street=_outsmart_pick(payload, ("CustomerStreet", "customer_street")),
            house_no=_outsmart_pick(payload, ("CustomerStreetNo", "CustomerHouseNo", "customer_house_no")),
            zip_code=_outsmart_pick(payload, ("CustomerZIP", "CustomerZipCode", "customer_zip")),
            city=_outsmart_pick(payload, ("CustomerCity", "customer_city")),
            remark="Synthetisch aus OutSmart-Arbeitsauftrag",
        )
    if invoice_debtor and invoice_debtor != customer_debtor:
        _customer_init_seed_outsmart_relation(
            db,
            debtor_no=invoice_debtor,
            name=_outsmart_pick(payload, ("CustomerNameInvoice", "customer_name_invoice", "CustomerInvoice")),
            street=_outsmart_pick(payload, ("CustomerStreetInvoice", "CustomerInvoiceStreet")),
            house_no=_outsmart_pick(payload, ("CustomerStreetNoInvoice", "CustomerInvoiceHouseNo")),
            zip_code=_outsmart_pick(payload, ("CustomerZIPInvoice", "CustomerInvoiceZipCode")),
            city=_outsmart_pick(payload, ("CustomerCityInvoice", "CustomerInvoiceCity")),
            remark="Synthetisch aus OutSmart-Arbeitsauftrag (Rechnungskunde)",
        )
    return "created" if created else "updated" if changed else "skipped"


