def _sevdesk_list_all(fetch_fn, *, page_size: int = 200, max_rows: int = 5000, progress_cb=None) -> list[dict]:
    rows: list[dict] = []
    offset = 0
    page_no = 0
    while len(rows) < max_rows:
        page_no += 1
        batch = fetch_fn(limit=page_size, offset=offset)
        if not batch:
            break
        rows.extend(batch)
        if callable(progress_cb):
            try:
                progress_cb(count=len(rows), page_no=page_no, batch_count=len(batch))
            except Exception:
                pass
        if len(batch) < page_size:
            break
        offset += page_size
    return rows[:max_rows]


def _customer_init_outsmart_payload_key(payload: dict) -> str:
    return (
        _outsmart_row_id(payload)
        or _outsmart_workorder_key(payload)
        or _outsmart_project_key(payload)
        or _outsmart_relation_key(payload)
        or json.dumps(payload, sort_keys=True, ensure_ascii=False)
    )


def _customer_init_collect_outsmart_workorders(settings: dict[str, str | bool], progress_cb=None) -> tuple[list[dict], list[str]]:
    warnings: list[str] = []
    rows: list[dict] = []
    seen: set[str] = set()

    def add_batch(batch: list[dict]) -> int:
        added = 0
        for payload in batch:
            key = _customer_init_outsmart_payload_key(payload)
            if key in seen:
                continue
            seen.add(key)
            rows.append(payload)
            added += 1
        return added

    def fetch_status_batches(status_value: str, label: str) -> None:
        page_size = 200
        offset = 0
        for page_no in range(1, 26):
            try:
                batch = _outsmart_extract_rows(
                    outsmart_fetch_workorders(
                        settings,
                        status=status_value,
                        update_status=False,
                        limit=page_size,
                        offset=offset,
                    )
                )
            except Exception as exc:
                message = str(exc)
                if "timed out" in message.lower():
                    warnings.append(f"{label} hat das Zeitlimit überschritten. Der Lauf verwendet nur die bis dahin lesbaren Arbeitsaufträge.")
                    return
                if "OutSmart-Fehler 404" in message and "\"code\":1001" in message:
                    warnings.append(f"{label} ist in dieser OutSmart-Instanz nicht verfügbar.")
                    return
                if page_no > 1:
                    warnings.append(f"{label} konnte ab Seite {page_no} nicht weiter gelesen werden: {message}")
                    return
                raise
            if not batch:
                return
            before = len(seen)
            add_batch(batch)
            if callable(progress_cb):
                try:
                    progress_cb(label=label, page_no=page_no, count=len(rows), batch_count=len(batch))
                except Exception:
                    pass
            if len(batch) < page_size:
                return
            if len(seen) == before:
                return
            offset += page_size

    fetch_status_batches("", "GetWorkorders")
    if len(rows) <= 1:
        for status_value, label in (
            ("Compleet", "GetWorkorders Status Compleet"),
            ("Gepland", "GetWorkorders Status Gepland"),
            ("Open", "GetWorkorders Status Open"),
            ("Nieuw", "GetWorkorders Status Nieuw"),
            ("InBehandeling", "GetWorkorders Status InBehandeling"),
            ("Gesloten", "GetWorkorders Status Gesloten"),
            ("Completed", "GetWorkorders Status Completed"),
            ("Planned", "GetWorkorders Status Planned"),
            ("Closed", "GetWorkorders Status Closed"),
        ):
            fetch_status_batches(status_value, label)
    return rows, warnings


def _customer_init_import_outsmart(db: Session, job: ExternalSyncJob | None = None) -> dict[str, int]:
    settings = _outsmart_settings(db, include_secret=True)
    created_job = job is None
    if job is None:
        job = _start_sync_job(
            db,
            system_name="outsmart",
            direction="pull",
            entity_type="customer_init_outsmart",
            job_key="customer_init_outsmart",
            lock_key="customer_init",
            title="OutSmart-Initialimport",
            log_text="Kunden-Initialisierung: OutSmart",
        )
    summary = {"relations": 0, "projects": 0, "workorders": 0, "errors": 0, "warnings": []}
    try:
        _sync_job_update_progress(
            db,
            job,
            phase="OutSmart-Daten werden geladen",
            phase_detail="Relationen, Projekte und Arbeitsaufträge werden aus OutSmart gelesen.",
            processed_count=0,
            success_count=0,
            error_count=0,
            commit=True,
        )
        relation_rows: list[dict] = []
        project_rows: list[dict] = []
        workorder_rows: list[dict] = []
        try:
            relation_rows = _outsmart_extract_rows(outsmart_fetch_relations(settings))
            _sync_job_update_progress(db, job, phase_detail=f"Relationen geladen: {len(relation_rows)}", current_item_label="OutSmart-Relationen", commit=True)
        except Exception as exc:
            message = str(exc)
            if "OutSmart-Fehler 404" in message and "\"code\":1001" in message:
                summary["warnings"].append("GetRelations ist in dieser OutSmart-Instanz nicht verfügbar. Relationen werden aus Projekten und Arbeitsaufträgen abgeleitet.")
            else:
                raise
        try:
            project_rows = _outsmart_extract_rows(outsmart_fetch_projects(settings))
            _sync_job_update_progress(db, job, phase_detail=f"Projekte geladen: {len(project_rows)}", current_item_label="OutSmart-Projekte", commit=True)
        except Exception as exc:
            message = str(exc)
            if "timed out" in message.lower():
                summary["warnings"].append("GetProjects hat das Zeitlimit überschritten. Projekte werden soweit möglich aus Arbeitsaufträgen abgeleitet.")
            elif "OutSmart-Fehler 404" in message and "\"code\":1001" in message:
                summary["warnings"].append("GetProjects ist in dieser OutSmart-Instanz nicht verfügbar. Projekte werden soweit möglich aus Arbeitsaufträgen abgeleitet.")
            else:
                raise
        workorder_rows, workorder_warnings = _customer_init_collect_outsmart_workorders(
            settings,
            progress_cb=lambda **info: _sync_job_update_progress(
                db,
                job,
                phase="OutSmart-Arbeitsaufträge werden geladen",
                phase_detail=f"{info.get('label') or 'GetWorkorders'} | Seite {int(info.get('page_no') or 0)} | bisher {int(info.get('count') or 0)}",
                current_item_label="OutSmart-Workorders",
                processed_count=int(info.get("count") or 0),
                commit=True,
            ),
        )
        summary["warnings"].extend(workorder_warnings)
        total_count = len(relation_rows) + len(project_rows) + len(workorder_rows)
        _sync_job_update_progress(
            db,
            job,
            phase="OutSmart-Stage-Daten werden gespeichert",
            phase_detail=f"Gesamt {total_count} Datensätze",
            total_count=total_count,
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="Stage-Import",
            commit=True,
        )
        processed_count = 0
        for payload in relation_rows:
            try:
                state = _customer_init_upsert_outsmart_relation_stage(db, payload)
                if state != "skipped":
                    summary["relations"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(payload.get("name") or payload.get("relation_no") or "OutSmart-Relation"),
                    current_item_ref=str(payload.get("relation_no") or payload.get("debtor_no") or ""),
                    processed_count=processed_count,
                    success_count=summary["relations"] + summary["projects"] + summary["workorders"],
                    error_count=summary["errors"],
                    commit=True,
                )
        relations_before_projects = int(db.query(OutsmartRelationStage).count())
        for payload in project_rows:
            try:
                state = _customer_init_upsert_outsmart_project_stage(db, payload)
                if state != "skipped":
                    summary["projects"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(payload.get("name") or payload.get("project_code") or "OutSmart-Projekt"),
                    current_item_ref=str(payload.get("project_code") or ""),
                    processed_count=processed_count,
                    success_count=summary["relations"] + summary["projects"] + summary["workorders"],
                    error_count=summary["errors"],
                    commit=True,
                )
        relations_before_workorders = int(db.query(OutsmartRelationStage).count())
        projects_before_workorders = int(db.query(OutsmartProjectStage).count())
        for payload in workorder_rows:
            try:
                state = _customer_init_upsert_outsmart_workorder_stage(db, payload)
                if state != "skipped":
                    summary["workorders"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(payload.get("CustomerName") or payload.get("customer_name") or payload.get("WorkorderNo") or "OutSmart-Workorder"),
                    current_item_ref=str(payload.get("WorkorderNo") or payload.get("workorder_no") or ""),
                    processed_count=processed_count,
                    success_count=summary["relations"] + summary["projects"] + summary["workorders"],
                    error_count=summary["errors"],
                    commit=True,
                )
        projects_after_workorders = int(db.query(OutsmartProjectStage).count())
        if projects_after_workorders > projects_before_workorders:
            summary["projects"] += projects_after_workorders - projects_before_workorders
        relations_after_projects = relations_before_workorders
        if relations_after_projects > relations_before_projects:
            summary["relations"] += relations_after_projects - relations_before_projects
        relations_after_workorders = int(db.query(OutsmartRelationStage).count())
        if relations_after_workorders > relations_before_workorders:
            summary["relations"] += relations_after_workorders - relations_before_workorders
        if not relation_rows and not project_rows and not workorder_rows:
            raise ValueError("OutSmart lieferte keine Seed-Daten für die Kunden-Initialisierung.")
        _sync_job_update_progress(
            db,
            job,
            phase="OutSmart-Initialimport abgeschlossen",
            phase_detail=f"Relationen {summary['relations']} | Projekte {summary['projects']} | Arbeitsaufträge {summary['workorders']}",
            total_count=total_count,
            processed_count=total_count,
            success_count=summary["relations"] + summary["projects"] + summary["workorders"],
            error_count=summary["errors"],
            current_item_label="Fertig",
            current_item_ref="",
            note=" | ".join([str(message) for message in summary.get("warnings") or []][:3]) or None,
            commit=False,
        )
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary, ensure_ascii=False))
        _customer_init_mark_now(db, CUSTOMER_INIT_LAST_OUTSMART_IMPORT_AT)
        return summary
    except Exception as exc:
        if created_job:
            _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


def _customer_init_import_sevdesk(db: Session, job: ExternalSyncJob | None = None) -> dict[str, int]:
    settings = _sevdesk_settings(db, include_secret=True)
    created_job = job is None
    if job is None:
        job = _start_sync_job(
            db,
            system_name="sevdesk",
            direction="pull",
            entity_type="customer_init_sevdesk",
            job_key="customer_init_sevdesk",
            lock_key="customer_init",
            title="sevDesk-Initialimport",
            log_text="Kunden-Initialisierung: sevDesk",
        )
    summary = {"contacts": 0, "orders": 0, "invoices": 0, "stats": 0, "errors": 0}
    try:
        _sync_job_update_progress(
            db,
            job,
            phase="sevDesk-Daten werden geladen",
            phase_detail="Kontakte, Angebote und Rechnungen werden gelesen.",
            processed_count=0,
            success_count=0,
            error_count=0,
            commit=True,
        )
        contacts = _sevdesk_list_all(
            lambda **kw: sevdesk_list_contacts(settings, **kw),
            progress_cb=lambda **info: _sync_job_update_progress(
                db,
                job,
                phase="sevDesk-Kontakte werden geladen",
                phase_detail=f"Seite {int(info.get('page_no') or 0)} | bisher {int(info.get('count') or 0)} Kontakte",
                current_item_label="sevDesk-Kontakte",
                processed_count=int(info.get("count") or 0),
                commit=True,
            ),
        )
        orders = _sevdesk_list_all(
            lambda **kw: sevdesk_list_orders(settings, **kw),
            progress_cb=lambda **info: _sync_job_update_progress(
                db,
                job,
                phase="sevDesk-Angebote werden geladen",
                phase_detail=f"Seite {int(info.get('page_no') or 0)} | bisher {int(info.get('count') or 0)} Angebote",
                current_item_label="sevDesk-Angebote",
                commit=True,
            ),
        )
        invoices = _sevdesk_list_all(
            lambda **kw: sevdesk_list_invoices(settings, **kw),
            progress_cb=lambda **info: _sync_job_update_progress(
                db,
                job,
                phase="sevDesk-Rechnungen werden geladen",
                phase_detail=f"Seite {int(info.get('page_no') or 0)} | bisher {int(info.get('count') or 0)} Rechnungen",
                current_item_label="sevDesk-Rechnungen",
                commit=True,
            ),
        )
        total_count = len(contacts) + len(orders) + len(invoices)
        _sync_job_update_progress(
            db,
            job,
            phase="sevDesk-Stage-Daten werden gespeichert",
            phase_detail=f"Gesamt {total_count} Datensätze",
            total_count=total_count,
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="Stage-Import",
            commit=True,
        )
        processed_count = 0
        for payload in contacts:
            try:
                state = _customer_init_upsert_sevdesk_contact_stage(db, payload)
                if state != "skipped":
                    summary["contacts"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(payload.get("name") or payload.get("customerNumber") or "sevDesk-Kontakt"),
                    current_item_ref=sevdesk_first_value(payload, ("customerNumber", "id", "ID")),
                    processed_count=processed_count,
                    success_count=summary["contacts"] + summary["orders"] + summary["invoices"] + summary["stats"],
                    error_count=summary["errors"],
                    commit=True,
                )
        for payload in orders:
            try:
                state = _customer_init_upsert_sevdesk_order_stage(db, payload)
                if state != "skipped":
                    summary["orders"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(sevdesk_first_value(payload, ("orderNumber", "name", "id")) or "sevDesk-Angebot"),
                    current_item_ref=sevdesk_first_value(payload, ("orderNumber", "id")),
                    processed_count=processed_count,
                    success_count=summary["contacts"] + summary["orders"] + summary["invoices"] + summary["stats"],
                    error_count=summary["errors"],
                    commit=True,
                )
        for payload in invoices:
            try:
                state = _customer_init_upsert_sevdesk_invoice_stage(db, payload)
                if state != "skipped":
                    summary["invoices"] += 1
            except Exception:
                summary["errors"] += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(sevdesk_first_value(payload, ("invoiceNumber", "id")) or "sevDesk-Rechnung"),
                    current_item_ref=sevdesk_first_value(payload, ("invoiceNumber", "id")),
                    processed_count=processed_count,
                    success_count=summary["contacts"] + summary["orders"] + summary["invoices"] + summary["stats"],
                    error_count=summary["errors"],
                    commit=True,
                )
        stats_by_contact: dict[str, dict[str, int]] = {}
        for payload in orders:
            contact = sevdesk_first_value(payload, ("contact.id", "contact", "contact_id"))
            if isinstance(payload.get("contact"), dict):
                contact = sevdesk_first_value(payload.get("contact"), ("id", "ID")) or contact
            if not contact:
                continue
            entry = stats_by_contact.setdefault(str(contact), {"order_count": 0, "invoice_count": 0, "credit_note_count": 0, "voucher_count": 0})
            entry["order_count"] += 1
        for payload in invoices:
            contact = sevdesk_first_value(payload, ("contact.id", "contact", "contact_id"))
            if isinstance(payload.get("contact"), dict):
                contact = sevdesk_first_value(payload.get("contact"), ("id", "ID")) or contact
            if not contact:
                continue
            entry = stats_by_contact.setdefault(str(contact), {"order_count": 0, "invoice_count": 0, "credit_note_count": 0, "voucher_count": 0})
            invoice_type = _crm_normalize_key(sevdesk_first_value(payload, ("invoiceType", "type")))
            if "credit" in invoice_type or "gutschrift" in invoice_type:
                entry["credit_note_count"] += 1
            else:
                entry["invoice_count"] += 1
        for contact_id, counts in stats_by_contact.items():
            try:
                state = _customer_init_upsert_sevdesk_contact_stats_stage(db, contact_id=contact_id, counts=counts)
                if state != "skipped":
                    summary["stats"] += 1
            except Exception:
                summary["errors"] += 1
        _sync_job_update_progress(
            db,
            job,
            phase="sevDesk-Initialimport abgeschlossen",
            phase_detail=f"Kontakte {summary['contacts']} | Angebote {summary['orders']} | Rechnungen {summary['invoices']}",
            total_count=total_count,
            processed_count=total_count,
            success_count=summary["contacts"] + summary["orders"] + summary["invoices"] + summary["stats"],
            error_count=summary["errors"],
            current_item_label="Fertig",
            current_item_ref="",
            commit=False,
        )
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary, ensure_ascii=False))
        _customer_init_mark_now(db, CUSTOMER_INIT_LAST_SEVDESK_IMPORT_AT)
        return summary
    except Exception as exc:
        if created_job:
            _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


def _customer_init_existing_customer_for_members(db: Session, members: list[dict]) -> tuple[int | None, str]:
    customer_ids: set[int] = set()
    for member in members:
        system_name = _crm_normalize_key(member.get("source_system"))
        source_type = _crm_normalize_key(member.get("source_type"))
        key = str(member.get("external_key") or "").strip()
        secondary = str(member.get("external_secondary_key") or "").strip()
        if system_name == "outsmart":
            keys = [value for value in (key, secondary) if value]
            if keys:
                identity_rows = db.query(ExternalIdentity).filter(
                    ExternalIdentity.system_name == "outsmart",
                    ExternalIdentity.external_key.in_(keys),
                ).all()
                customer_ids.update(int(row.master_customer_id) for row in identity_rows if int(row.master_customer_id or 0) > 0)
                link_rows = db.query(ExternalLink).filter(
                    ExternalLink.system_name == "outsmart",
                    ExternalLink.object_type == "master_customer",
                    ExternalLink.external_key.in_(keys),
                ).all()
                customer_ids.update(int(row.object_id) for row in link_rows if int(row.object_id or 0) > 0)
        if system_name == "sevdesk":
            keys = [value for value in (key, secondary) if value]
            if keys:
                identity_rows = db.query(ExternalIdentity).filter(
                    ExternalIdentity.system_name == "sevdesk",
                    or_(ExternalIdentity.external_key.in_(keys), ExternalIdentity.external_id.in_(keys)),
                ).all()
                customer_ids.update(int(row.master_customer_id) for row in identity_rows if int(row.master_customer_id or 0) > 0)
        if system_name == "outsmart" and source_type == "relation_stage" and secondary:
            identity_rows = db.query(ExternalIdentity).filter(
                ExternalIdentity.system_name == "outsmart",
                ExternalIdentity.external_type == "debtor",
                ExternalIdentity.external_key == secondary,
            ).all()
            customer_ids.update(int(row.master_customer_id) for row in identity_rows if int(row.master_customer_id or 0) > 0)
    if len(customer_ids) == 1:
        return next(iter(customer_ids)), ""
    if len(customer_ids) > 1:
        return None, "Mehrere bestehende Master-Kunden passen zu diesem Cluster."
    return None, ""


def _customer_init_build_clusters(db: Session, job: ExternalSyncJob | None = None) -> dict[str, int]:
    created_job = job is None
    if job is None:
        job = _start_sync_job(
            db,
            system_name="local",
            direction="pull",
            entity_type="customer_init_matching",
            job_key="customer_init_matching",
            lock_key="customer_init",
            title="Kunden-Matching",
            log_text="Kunden-Initialisierung: Matching",
        )
    try:
        stage_total = (
            int(db.query(OutsmartRelationStage).count())
            + int(db.query(OutsmartProjectStage).count())
            + int(db.query(OutsmartWorkorderStage).count())
            + int(db.query(SevdeskContactStage).count())
            + int(db.query(SevdeskOrderStage).count())
            + int(db.query(SevdeskInvoiceStage).count())
            + int(db.query(SevdeskContactStatsStage).count())
        )
        _sync_job_update_progress(
            db,
            job,
            phase="Matching-Regeln werden berechnet",
            phase_detail=f"{stage_total} Stage-Datensätze werden ausgewertet.",
            total_count=0,
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="Clusterregeln",
            commit=True,
        )
        payloads = build_customer_init_clusters(
            outsmart_relations=[
                {
                    "id": row.id,
                    "relation_no": row.relation_no,
                    "debtor_no": row.debtor_no,
                    "name": row.name,
                    "city": row.city,
                    "zip_code": row.zip_code,
                    "email_norm": row.email_norm,
                    "phone_norm": row.phone_norm,
                    "name_norm": row.name_norm,
                    "zip_norm": row.zip_norm,
                    "debtor_norm": row.debtor_norm,
                }
                for row in db.query(OutsmartRelationStage).all()
            ],
            outsmart_projects=[
                {
                    "id": row.id,
                    "project_code": row.project_code,
                    "debtor_number_invoice": row.debtor_number_invoice,
                    "name": row.name,
                    "status": row.status,
                    "debtor_norm": row.debtor_norm,
                    "customer_number_norm": row.customer_number_norm,
                }
                for row in db.query(OutsmartProjectStage).all()
            ],
            outsmart_workorders=[
                {
                    "id": row.id,
                    "workorder_no": row.workorder_no,
                    "customer_name": row.customer_name,
                    "project_code": row.project_code,
                    "status": row.status,
                    "debtor_norm": row.debtor_norm,
                    "customer_number_norm": row.customer_number_norm,
                }
                for row in db.query(OutsmartWorkorderStage).all()
            ],
            sevdesk_contacts=[
                {
                    "id": row.id,
                    "sevdesk_contact_id": row.sevdesk_contact_id,
                    "customer_number": row.customer_number,
                    "name": row.name,
                    "city": row.city,
                    "zip_code": row.zip_code,
                    "name_norm": row.name_norm,
                    "street_norm": row.street_norm,
                    "zip_norm": row.zip_norm,
                    "city_norm": row.city_norm,
                    "email_norm": row.email_norm,
                    "phone_norm": row.phone_norm,
                    "customer_number_norm": row.customer_number_norm,
                }
                for row in db.query(SevdeskContactStage).all()
            ],
            sevdesk_orders=[
                {
                    "id": row.id,
                    "sevdesk_order_id": row.sevdesk_order_id,
                    "order_number": row.order_number,
                    "contact_id": row.contact_id,
                    "status": row.status,
                }
                for row in db.query(SevdeskOrderStage).all()
            ],
            sevdesk_invoices=[
                {
                    "id": row.id,
                    "sevdesk_invoice_id": row.sevdesk_invoice_id,
                    "invoice_number": row.invoice_number,
                    "contact_id": row.contact_id,
                    "status": row.status,
                }
                for row in db.query(SevdeskInvoiceStage).all()
            ],
            sevdesk_stats=[
                {
                    "id": row.id,
                    "sevdesk_contact_id": row.sevdesk_contact_id,
                    "order_count": row.order_count,
                    "invoice_count": row.invoice_count,
                    "credit_note_count": row.credit_note_count,
                    "voucher_count": row.voucher_count,
                }
                for row in db.query(SevdeskContactStatsStage).all()
            ],
        )
        _sync_job_update_progress(
            db,
            job,
            phase="Cluster werden gespeichert",
            phase_detail=f"{len(payloads)} Cluster werden geschrieben.",
            total_count=len(payloads),
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="Cluster",
            commit=True,
        )
        seen_keys: set[str] = set()
        processed_count = 0
        for payload in payloads:
            cluster_key = str(payload.get("cluster_key") or "").strip()
            if not cluster_key:
                continue
            seen_keys.add(cluster_key)
            row = db.query(CustomerInitCluster).filter(CustomerInitCluster.cluster_key == cluster_key).one_or_none()
            created = row is None
            if row is None:
                row = CustomerInitCluster(cluster_key=cluster_key, created_at=_utcnow_naive())
            existing_customer_id, conflict_note = _customer_init_existing_customer_for_members(db, payload.get("members") or [])
            if row.status != "materialized":
                row.status = str(payload.get("status") or "ready")
            if conflict_note:
                row.status = "needs_review"
            row.anchor_system = str(payload.get("anchor_system") or "local")
            row.anchor_key = str(payload.get("anchor_key") or "").strip() or None
            row.display_name = str(payload.get("display_name") or "").strip() or None
            row.confidence = float(payload.get("confidence") or 0.0)
            row.conflict_note = conflict_note or str(payload.get("conflict_note") or "").strip() or None
            if existing_customer_id and row.master_customer_id in (None, 0):
                row.master_customer_id = int(existing_customer_id)
            row.summary_json = json.dumps(payload.get("summary") or {}, ensure_ascii=False)
            row.updated_at = _utcnow_naive()
            db.add(row)
            db.flush()
            db.query(CustomerInitClusterMember).filter(CustomerInitClusterMember.cluster_id == int(row.id)).delete()
            for member in payload.get("members") or []:
                db.add(
                    CustomerInitClusterMember(
                        cluster_id=int(row.id),
                        source_system=str(member.get("source_system") or "").strip(),
                        source_type=str(member.get("source_type") or "").strip(),
                        stage_row_id=int(member.get("stage_row_id") or 0) or None,
                        external_key=str(member.get("external_key") or "").strip() or None,
                        external_secondary_key=str(member.get("external_secondary_key") or "").strip() or None,
                        display_name=str(member.get("display_name") or "").strip() or None,
                        match_score=float(member.get("match_score") or 0.0) if member.get("match_score") is not None else None,
                        match_reason=str(member.get("match_reason") or "").strip() or None,
                        is_anchor=bool(member.get("is_anchor")),
                        meta_json=json.dumps(member.get("meta") or {}, ensure_ascii=False),
                        created_at=_utcnow_naive(),
                    )
                )
            processed_count += 1
            if processed_count == 1 or processed_count % 25 == 0 or processed_count == len(payloads):
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(payload.get("display_name") or cluster_key or "Cluster"),
                    current_item_ref=cluster_key,
                    processed_count=processed_count,
                    success_count=processed_count,
                    error_count=0,
                    commit=True,
                )
        stale_rows = (
            db.query(CustomerInitCluster)
            .filter(~CustomerInitCluster.cluster_key.in_(list(seen_keys) or ["__none__"]), CustomerInitCluster.status != "materialized")
            .all()
        )
        for row in stale_rows:
            db.query(CustomerInitClusterMember).filter(CustomerInitClusterMember.cluster_id == int(row.id)).delete()
            db.delete(row)
        summary = {
            "clusters": len(seen_keys),
            "ready": int(db.query(CustomerInitCluster).filter(CustomerInitCluster.status == "ready").count()),
            "needs_review": int(db.query(CustomerInitCluster).filter(CustomerInitCluster.status == "needs_review").count()),
            "materialized": int(db.query(CustomerInitCluster).filter(CustomerInitCluster.status == "materialized").count()),
        }
        _sync_job_update_progress(
            db,
            job,
            phase="Matching abgeschlossen",
            phase_detail=f"Cluster {summary['clusters']} | bereit {summary['ready']} | prüfen {summary['needs_review']}",
            total_count=len(payloads),
            processed_count=len(payloads),
            success_count=summary["clusters"],
            error_count=0,
            current_item_label="Fertig",
            current_item_ref="",
            commit=False,
        )
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary, ensure_ascii=False))
        _enqueue_sync_job(
            db,
            system_name="local",
            direction="pull",
            entity_type="customer_init_ai_review",
            title="KI-Review Kunden-Initialisierung",
            job_key="customer_init_ai_review",
            lock_key="customer_init",
            log_text="Kunden-Initialisierung: KI-Review",
            progress={
                "phase": "Wartet auf Start",
                "phase_detail": "KI-Review wurde nach dem Matching in die Warteschlange gestellt.",
                "processed_count": 0,
                "success_count": 0,
                "error_count": 0,
            },
            result_url="/system/kunden-initialisierung/review",
        )
        _customer_init_mark_now(db, CUSTOMER_INIT_LAST_MATCH_AT)
        return summary
    except Exception as exc:
        if created_job:
            _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


def _customer_init_pick_representative_member(db: Session, cluster_id: int) -> dict[str, object]:
    rows = (
        db.query(CustomerInitClusterMember)
        .filter(CustomerInitClusterMember.cluster_id == int(cluster_id))
        .order_by(CustomerInitClusterMember.is_anchor.desc(), CustomerInitClusterMember.match_score.desc(), CustomerInitClusterMember.id.asc())
        .all()
    )
    for row in rows:
        if _crm_normalize_key(row.source_type) == "relation_stage" and int(row.stage_row_id or 0) > 0:
            staged = db.get(OutsmartRelationStage, int(row.stage_row_id))
            if staged:
                return {
                    "display_name": staged.name,
                    "street": staged.street,
                    "house_no": staged.house_no,
                    "zip_code": staged.zip_code,
                    "city": staged.city,
                    "email": staged.email,
                    "phone": staged.phone,
                }
    for row in rows:
        if _crm_normalize_key(row.source_type) == "contact_stage" and int(row.stage_row_id or 0) > 0:
            staged = db.get(SevdeskContactStage, int(row.stage_row_id))
            if staged:
                return {
                    "display_name": staged.name,
                    "street": staged.street,
                    "house_no": None,
                    "zip_code": staged.zip_code,
                    "city": staged.city,
                    "email": staged.email,
                    "phone": staged.phone,
                }
    return {"display_name": None, "street": None, "house_no": None, "zip_code": None, "city": None, "email": None, "phone": None}


def _customer_init_upsert_cluster_identities(db: Session, customer: MasterCustomer, cluster: CustomerInitCluster) -> None:
    members = (
        db.query(CustomerInitClusterMember)
        .filter(CustomerInitClusterMember.cluster_id == int(cluster.id))
        .order_by(CustomerInitClusterMember.is_anchor.desc(), CustomerInitClusterMember.id.asc())
        .all()
    )
    outsmart_primary_exists = any(
        _crm_normalize_key(row.system_name) == "outsmart" and bool(row.is_primary)
        for row in db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id == int(customer.id)).all()
    )
    sevdesk_primary_exists = any(
        _crm_normalize_key(row.system_name) == "sevdesk" and bool(row.is_primary)
        for row in db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id == int(customer.id)).all()
    )
    for member in members:
        system_name = _crm_normalize_key(member.source_system)
        source_type = _crm_normalize_key(member.source_type)
        key = str(member.external_key or "").strip()
        secondary = str(member.external_secondary_key or "").strip()
        if system_name == "outsmart" and source_type == "relation_stage":
            if key:
                row = (
                    db.query(ExternalIdentity)
                    .filter(
                        ExternalIdentity.system_name == "outsmart",
                        ExternalIdentity.external_type == "relation",
                        ExternalIdentity.external_key == key,
                    )
                    .one_or_none()
                )
                if row is None:
                    row = ExternalIdentity(system_name="outsmart", external_type="relation", external_key=key, created_at=_utcnow_naive())
                row.master_customer_id = int(customer.id)
                row.external_id = secondary or None
                row.is_primary = not outsmart_primary_exists
                db.add(row)
                outsmart_primary_exists = True
                _upsert_external_link(
                    db,
                    system_name="outsmart",
                    object_type="master_customer",
                    object_id=int(customer.id),
                    external_key=key,
                    external_row_id=secondary or None,
                )
            if secondary:
                row = (
                    db.query(ExternalIdentity)
                    .filter(
                        ExternalIdentity.system_name == "outsmart",
                        ExternalIdentity.external_type == "debtor",
                        ExternalIdentity.external_key == secondary,
                    )
                    .one_or_none()
                )
                if row is None:
                    row = ExternalIdentity(system_name="outsmart", external_type="debtor", external_key=secondary, created_at=_utcnow_naive())
                row.master_customer_id = int(customer.id)
                row.external_id = key or None
                row.is_primary = False
                db.add(row)
        if system_name == "sevdesk" and source_type == "contact_stage":
            if key:
                row = (
                    db.query(ExternalIdentity)
                    .filter(
                        ExternalIdentity.system_name == "sevdesk",
                        ExternalIdentity.external_type == "contact",
                        ExternalIdentity.external_key == key,
                    )
                    .one_or_none()
                )
                if row is None:
                    row = ExternalIdentity(system_name="sevdesk", external_type="contact", external_key=key, created_at=_utcnow_naive())
                row.master_customer_id = int(customer.id)
                row.external_id = key
                row.is_primary = not sevdesk_primary_exists
                row.note = "Initialisierung"
                db.add(row)
                sevdesk_primary_exists = True
            if secondary:
                row = (
                    db.query(ExternalIdentity)
                    .filter(
                        ExternalIdentity.system_name == "sevdesk",
                        ExternalIdentity.external_type == "customernumber",
                        ExternalIdentity.external_key == secondary,
                    )
                    .one_or_none()
                )
                if row is None:
                    row = ExternalIdentity(system_name="sevdesk", external_type="customernumber", external_key=secondary, created_at=_utcnow_naive())
                row.master_customer_id = int(customer.id)
                row.external_id = key or None
                row.is_primary = False
                db.add(row)


def _customer_init_materialize_cluster(db: Session, cluster: CustomerInitCluster) -> tuple[MasterCustomer, bool]:
    customer = db.get(MasterCustomer, int(cluster.master_customer_id or 0)) if int(cluster.master_customer_id or 0) > 0 else None
    source = _customer_init_pick_representative_member(db, int(cluster.id))
    created = False
    if customer is None:
        party = Party(
            party_type="company",
            display_name=str(source.get("display_name") or cluster.display_name or cluster.cluster_key),
            active=True,
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(party)
        db.flush()
        customer = MasterCustomer(
            party_id=int(party.id),
            customer_no_internal=_crm_next_customer_no(db),
            status="active",
            note="Automatisch aus Kunden-Initialisierung erzeugt.",
            created_at=_utcnow_naive(),
            updated_at=_utcnow_naive(),
        )
        db.add(customer)
        db.flush()
        created = True
    else:
        party = db.get(Party, int(customer.party_id))
        if party and not str(party.display_name or "").strip() and str(source.get("display_name") or "").strip():
            party.display_name = str(source.get("display_name") or "").strip()
            party.updated_at = _utcnow_naive()
            db.add(party)
    if customer and customer.party_id:
        existing_address = (
            db.query(CrmAddress)
            .filter(CrmAddress.party_id == int(customer.party_id))
            .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
            .first()
        )
        if existing_address is None and any(str(source.get(key) or "").strip() for key in ("street", "zip_code", "city", "email", "phone")):
            address = CrmAddress(
                party_id=int(customer.party_id),
                label="Hauptadresse",
                street=str(source.get("street") or "").strip() or None,
                house_no=str(source.get("house_no") or "").strip() or None,
                zip_code=str(source.get("zip_code") or "").strip() or None,
                city=str(source.get("city") or "").strip() or None,
                country_code="DE",
                email=str(source.get("email") or "").strip() or None,
                phone=str(source.get("phone") or "").strip() or None,
                is_default=True,
                active=True,
            )
            db.add(address)
            db.flush()
        existing_location = (
            db.query(ServiceLocation)
            .filter(ServiceLocation.master_customer_id == int(customer.id))
            .order_by(ServiceLocation.id.asc())
            .first()
        )
        if existing_location is None:
            default_address = (
                db.query(CrmAddress)
                .filter(CrmAddress.party_id == int(customer.party_id))
                .order_by(CrmAddress.is_default.desc(), CrmAddress.id.asc())
                .first()
            )
            if default_address:
                label = _crm_clean_text(f"{str(source.get('city') or '').strip()} {str(source.get('street') or '').strip()}") or "Hauptstandort"
                db.add(
                    ServiceLocation(
                        master_customer_id=int(customer.id),
                        party_id=int(customer.party_id),
                        address_id=int(default_address.id),
                        location_label=label,
                        active=True,
                    )
                )
    _customer_init_upsert_cluster_identities(db, customer, cluster)
    _crm_backfill_customer_contact_data(db, customer)
    cluster.master_customer_id = int(customer.id)
    cluster.status = "materialized"
    cluster.updated_at = _utcnow_naive()
    db.add(cluster)
    return customer, created


def _customer_init_materialize_ready_clusters(db: Session, job: ExternalSyncJob | None = None) -> dict[str, int]:
    created_job = job is None
    if job is None:
        job = _start_sync_job(
            db,
            system_name="local",
            direction="pull",
            entity_type="customer_init_materialize",
            job_key="customer_init_materialize",
            lock_key="customer_init",
            title="Master-Kunden erzeugen",
            log_text="Kunden-Initialisierung: Übernahme",
        )
    created = 0
    updated = 0
    skipped = 0
    try:
        rows = (
            db.query(CustomerInitCluster)
            .filter(CustomerInitCluster.status.in_(("ready", "materialized")))
            .order_by(CustomerInitCluster.anchor_system.asc(), CustomerInitCluster.id.asc())
            .all()
        )
        total_count = len(rows)
        _sync_job_update_progress(
            db,
            job,
            phase="Master-Kunden werden erzeugt",
            phase_detail=f"{total_count} Cluster werden übernommen oder geprüft.",
            total_count=total_count,
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="Materialisierung",
            commit=True,
        )
        processed_count = 0
        for row in rows:
            if _crm_normalize_key(row.status) == "materialized" and int(row.master_customer_id or 0) > 0:
                skipped += 1
                processed_count += 1
                continue
            customer, was_created = _customer_init_materialize_cluster(db, row)
            if was_created:
                created += 1
            else:
                updated += 1
            _crm_add_timeline_event(
                db,
                master_customer_id=int(customer.id),
                source_system="local",
                event_type="customer_init",
                title="Kunde aus Initialisierung übernommen",
                body=str(row.display_name or row.cluster_key),
                event_ts=_utcnow_naive(),
                external_ref=row.cluster_key,
                meta={"cluster_id": int(row.id)},
            )
            processed_count += 1
            if processed_count == 1 or processed_count % 10 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(row.display_name or row.cluster_key or "Cluster"),
                    current_item_ref=str(row.cluster_key or ""),
                    processed_count=processed_count,
                    success_count=created + updated,
                    error_count=0,
                    commit=True,
                )
        summary = {"created": created, "updated": updated, "skipped": skipped}
        _sync_job_update_progress(
            db,
            job,
            phase="Materialisierung abgeschlossen",
            phase_detail=f"Neu {created} | aktualisiert {updated} | übersprungen {skipped}",
            total_count=total_count,
            processed_count=total_count,
            success_count=created + updated,
            error_count=0,
            current_item_label="Fertig",
            current_item_ref="",
            commit=False,
        )
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary, ensure_ascii=False))
        _customer_init_mark_now(db, CUSTOMER_INIT_LAST_MATERIALIZE_AT)
        return summary
    except Exception as exc:
        if created_job:
            _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


def _customer_init_dashboard_context(db: Session) -> dict[str, object]:
    return {
        "init_mode": _customer_init_mode(db),
        "stage_counts": _customer_init_stage_counts(db),
        "cluster_counts": _customer_init_cluster_counts(db),
        "recent_jobs": _customer_init_recent_jobs(db, limit=12),
        "last_outsmart_import_at": _system_setting_get(db, CUSTOMER_INIT_LAST_OUTSMART_IMPORT_AT, ""),
        "last_sevdesk_import_at": _system_setting_get(db, CUSTOMER_INIT_LAST_SEVDESK_IMPORT_AT, ""),
        "last_match_at": _system_setting_get(db, CUSTOMER_INIT_LAST_MATCH_AT, ""),
        "last_materialize_at": _system_setting_get(db, CUSTOMER_INIT_LAST_MATERIALIZE_AT, ""),
    }


def _customer_init_cluster_ordering():
    return (
        case((CustomerInitCluster.status == "needs_review", 0), (CustomerInitCluster.status == "ready", 1), else_=2),
        CustomerInitCluster.confidence.desc(),
        CustomerInitCluster.id.asc(),
    )


def _customer_init_ai_candidate_query(db: Session, cluster_ids: list[int] | None = None):
    query = db.query(CustomerInitCluster)
    selected_ids = [int(value) for value in cluster_ids or [] if int(value or 0) > 0]
    if selected_ids:
        return query.filter(CustomerInitCluster.id.in_(selected_ids))
    return query.filter(CustomerInitCluster.status == "needs_review")


def _customer_init_cluster_ai_input(
    db: Session,
    cluster: CustomerInitCluster,
    *,
    members: list[CustomerInitClusterMember] | None = None,
    summary: dict[str, object] | None = None,
    customer: MasterCustomer | None = None,
) -> dict[str, object]:
    member_rows = members if members is not None else (
        db.query(CustomerInitClusterMember)
        .filter(CustomerInitClusterMember.cluster_id == int(cluster.id))
        .order_by(CustomerInitClusterMember.is_anchor.desc(), CustomerInitClusterMember.match_score.desc(), CustomerInitClusterMember.id.asc())
        .all()
    )
    summary_payload = summary if isinstance(summary, dict) else _json_dict(cluster.summary_json)
    customer_row = customer or (db.get(MasterCustomer, int(cluster.master_customer_id or 0)) if int(cluster.master_customer_id or 0) > 0 else None)
    members_payload: list[dict[str, object]] = []
    for member in member_rows[:4]:
        members_payload.append(
            {
                "source_system": str(member.source_system or ""),
                "source_type": str(member.source_type or ""),
                "display_name": str(member.display_name or ""),
                "external_key": str(member.external_key or ""),
                "external_secondary_key": str(member.external_secondary_key or ""),
                "match_score": float(member.match_score or 0.0) if member.match_score is not None else 0.0,
                "match_reason": str(member.match_reason or ""),
                "is_anchor": bool(member.is_anchor),
            }
        )
    return {
        "cluster_id": int(cluster.id),
        "cluster_key": str(cluster.cluster_key or ""),
        "display_name": str(cluster.display_name or cluster.cluster_key or ""),
        "cluster_status": str(cluster.status or ""),
        "cluster_confidence": float(cluster.confidence or 0.0),
        "anchor_system": str(cluster.anchor_system or ""),
        "anchor_key": str(cluster.anchor_key or ""),
        "conflict_note": str(cluster.conflict_note or ""),
        "master_customer_id": int(customer_row.id) if customer_row else None,
        "master_customer_no": str(customer_row.customer_no_internal or "") if customer_row else "",
        "summary": summary_payload,
        "members": members_payload,
    }


def _customer_init_ai_decision_maps(
    db: Session,
    cluster_ids: list[int],
) -> tuple[dict[int, AiDecisionLog], dict[int, AiReviewQueueItem]]:
    cluster_keys = [int(value) for value in cluster_ids if int(value or 0) > 0]
    if not cluster_keys:
        return {}, {}
    decisions = (
        db.query(AiDecisionLog)
        .filter(
            AiDecisionLog.task_name == "customer_init_cluster_review",
            AiDecisionLog.related_object_type == "customer_init_cluster",
            AiDecisionLog.related_object_id.in_(cluster_keys),
        )
        .order_by(AiDecisionLog.created_at.desc(), AiDecisionLog.id.desc())
        .all()
    )
    decision_map: dict[int, AiDecisionLog] = {}
    for row in decisions:
        key = int(row.related_object_id or 0)
        if key > 0 and key not in decision_map:
            decision_map[key] = row
    review_map: dict[int, AiReviewQueueItem] = {}
    decision_ids = [int(row.id) for row in decision_map.values()]
    if decision_ids:
        review_rows = (
            db.query(AiReviewQueueItem)
            .filter(AiReviewQueueItem.ai_decision_log_id.in_(decision_ids))
            .order_by(AiReviewQueueItem.id.desc())
            .all()
        )
        for row in review_rows:
            key = int(row.ai_decision_log_id or 0)
            if key > 0 and key not in review_map:
                review_map[key] = row
    return decision_map, review_map


def _customer_init_apply_ai_output(db: Session, cluster: CustomerInitCluster, output: dict[str, object]) -> str:
    suggested_status = _crm_normalize_key(str(output.get("recommended_status") or ""))
    if suggested_status not in CUSTOMER_INIT_CLUSTER_STATUS_CHOICES:
        suggested_status = "needs_review"
    if bool(output.get("hard_case")) and suggested_status == "ready":
        suggested_status = "needs_review"
    suggested_customer_id = _to_int(output.get("suggested_master_customer_id"), 0)
    if suggested_customer_id > 0:
        customer = db.get(MasterCustomer, suggested_customer_id)
        if customer is not None:
            cluster.master_customer_id = int(customer.id)
    cluster.status = suggested_status
    cluster.updated_at = _utcnow_naive()
    db.add(cluster)
    db.flush()
    return suggested_status


def _customer_init_ai_review_cluster(
    db: Session,
    cluster: CustomerInitCluster,
    *,
    members: list[CustomerInitClusterMember] | None = None,
    summary: dict[str, object] | None = None,
    customer: MasterCustomer | None = None,
    settings: dict[str, object] | None = None,
    force_refresh: bool = False,
) -> dict[str, object]:
    payload = _customer_init_cluster_ai_input(db, cluster, members=members, summary=summary, customer=customer)
    openai_settings = settings if isinstance(settings, dict) else _openai_settings(db, include_secret=True)
    return ai_review_customer_init_cluster(
        db,
        settings=openai_settings,
        input_payload=payload,
        related_object_id=int(cluster.id),
        force_refresh=force_refresh,
    )


def _customer_init_ai_review_clusters(
    db: Session,
    job: ExternalSyncJob | None = None,
    *,
    cluster_ids: list[int] | None = None,
    force_refresh: bool = False,
) -> dict[str, int]:
    created_job = job is None
    if job is None:
        job = _start_sync_job(
            db,
            system_name="local",
            direction="pull",
            entity_type="customer_init_ai_review",
            job_key="customer_init_ai_review",
            lock_key="customer_init",
            title="KI-Review Kunden-Initialisierung",
            log_text="Kunden-Initialisierung: KI-Review",
        )
    try:
        cluster_id_values = [int(value) for value in cluster_ids or [] if int(value or 0) > 0]
        rows = _customer_init_ai_candidate_query(db, cluster_id_values).order_by(*_customer_init_cluster_ordering()).all()
        total_count = len(rows)
        _sync_job_update_progress(
            db,
            job,
            phase="KI prueft Cluster",
            phase_detail=f"{total_count} unsichere Cluster werden fachlich bewertet.",
            total_count=total_count,
            processed_count=0,
            success_count=0,
            error_count=0,
            current_item_label="KI-Review",
            local_decision_count=0,
            openai_decision_count=0,
            cached_decision_count=0,
            note="Lokal 0 | OpenAI 0 | Cache 0",
            commit=True,
        )
        settings = _openai_settings(db, include_secret=True)
        auto_ready = 0
        auto_rejected = 0
        manual_review = 0
        review_queue = 0
        local_decisions = 0
        openai_decisions = 0
        cached_decisions = 0
        processed_count = 0
        cluster_keys = [int(row.id) for row in rows]
        member_rows = (
            db.query(CustomerInitClusterMember)
            .filter(CustomerInitClusterMember.cluster_id.in_(cluster_keys or [0]))
            .order_by(
                CustomerInitClusterMember.cluster_id.asc(),
                CustomerInitClusterMember.is_anchor.desc(),
                CustomerInitClusterMember.match_score.desc(),
                CustomerInitClusterMember.id.asc(),
            )
            .all()
        ) if cluster_keys else []
        member_map: dict[int, list[CustomerInitClusterMember]] = {}
        for member in member_rows:
            member_map.setdefault(int(member.cluster_id), []).append(member)
        customer_ids = [int(row.master_customer_id or 0) for row in rows if int(row.master_customer_id or 0) > 0]
        customer_map = {
            int(row.id): row
            for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_(customer_ids or [0])).all()
        } if customer_ids else {}
        for cluster in rows:
            members = list(member_map.get(int(cluster.id), []))
            summary = _json_dict(cluster.summary_json)
            customer = customer_map.get(int(cluster.master_customer_id or 0))
            result = _customer_init_ai_review_cluster(
                db,
                cluster,
                members=members,
                summary=summary,
                customer=customer,
                settings=settings,
                force_refresh=force_refresh,
            )
            if result.get("cached"):
                cached_decisions += 1
            else:
                model_name = str(getattr(result.get("log"), "model_name", "") or "")
                if model_name and model_name != "local-heuristic":
                    openai_decisions += 1
                else:
                    local_decisions += 1
            output = result.get("output") if isinstance(result.get("output"), dict) else {}
            suggested_status = _crm_normalize_key(str(output.get("recommended_status") or "needs_review"))
            if bool(output.get("hard_case")):
                suggested_status = "needs_review"
            if suggested_status not in CUSTOMER_INIT_CLUSTER_STATUS_CHOICES:
                suggested_status = "needs_review"
            if suggested_status in ("ready", "rejected") and not bool(output.get("hard_case")):
                applied_status = _customer_init_apply_ai_output(db, cluster, output)
                if applied_status == "ready":
                    auto_ready += 1
                elif applied_status == "rejected":
                    auto_rejected += 1
            else:
                cluster.status = "needs_review"
                cluster.updated_at = _utcnow_naive()
                db.add(cluster)
                db.flush()
                manual_review += 1
            if result.get("review_item") is not None:
                review_queue += 1
            processed_count += 1
            if processed_count == 1 or processed_count % 10 == 0 or processed_count == total_count:
                _sync_job_update_progress(
                    db,
                    job,
                    current_item_label=str(cluster.display_name or cluster.cluster_key or "Cluster"),
                    current_item_ref=str(cluster.cluster_key or ""),
                    processed_count=processed_count,
                    success_count=auto_ready + auto_rejected,
                    error_count=0,
                    local_decision_count=local_decisions,
                    openai_decision_count=openai_decisions,
                    cached_decision_count=cached_decisions,
                    note=f"Lokal {local_decisions} | OpenAI {openai_decisions} | Cache {cached_decisions}",
                    commit=True,
                )
        summary_payload = {
            "checked": total_count,
            "auto_ready": auto_ready,
            "auto_rejected": auto_rejected,
            "manual_review": manual_review,
            "review_queue": review_queue,
            "local_decisions": local_decisions,
            "openai_decisions": openai_decisions,
            "cached_decisions": cached_decisions,
        }
        _sync_job_update_progress(
            db,
            job,
            phase="KI-Review abgeschlossen",
            phase_detail=f"Bereit {auto_ready} | zur Pruefung {manual_review} | zurueckgestellt {auto_rejected}",
            total_count=total_count,
            processed_count=total_count,
            success_count=auto_ready + auto_rejected,
            error_count=0,
            local_decision_count=local_decisions,
            openai_decision_count=openai_decisions,
            cached_decision_count=cached_decisions,
            current_item_label="Fertig",
            current_item_ref="",
            note=f"Lokal {local_decisions} | OpenAI {openai_decisions} | Cache {cached_decisions}",
            commit=False,
        )
        _finish_sync_job(db, job, status="done", log_text=json.dumps(summary_payload, ensure_ascii=False), result_url="/system/kunden-initialisierung/review")
        return summary_payload
    except Exception as exc:
        if created_job:
            _finish_sync_job(db, job, status="failed", log_text=str(exc))
        raise


def _customer_init_review_rows(db: Session, status: str = "", focus_cluster_id: int = 0, limit: int = 40) -> list[dict[str, object]]:
    query = db.query(CustomerInitCluster)
    status_norm = _crm_normalize_key(status)
    if status_norm == "open":
        query = query.filter(CustomerInitCluster.status.in_(("ready", "needs_review")))
    elif status_norm in CUSTOMER_INIT_CLUSTER_STATUS_CHOICES:
        query = query.filter(CustomerInitCluster.status == status_norm)
    row_limit = max(1, min(int(limit or 40), 120))
    ordered_ids = [int(value) for value, in query.with_entities(CustomerInitCluster.id).order_by(*_customer_init_cluster_ordering()).limit(row_limit).all()]
    focus_id = int(focus_cluster_id or 0)
    if focus_id > 0 and focus_id not in ordered_ids:
        focus_row = db.get(CustomerInitCluster, focus_id)
        if focus_row is not None:
            focus_status = _crm_normalize_key(focus_row.status)
            if status_norm in ("", "open") and focus_status in ("ready", "needs_review"):
                ordered_ids.insert(0, focus_id)
            elif status_norm == focus_status:
                ordered_ids.insert(0, focus_id)
    if not ordered_ids:
        return []
    rows = db.query(CustomerInitCluster).filter(CustomerInitCluster.id.in_(ordered_ids)).all()
    row_map = {int(row.id): row for row in rows}
    rows = [row_map[row_id] for row_id in ordered_ids if row_id in row_map]
    cluster_ids = [int(row.id) for row in rows]
    decision_map, review_map = _customer_init_ai_decision_maps(db, cluster_ids)
    member_rows = (
        db.query(CustomerInitClusterMember)
        .filter(CustomerInitClusterMember.cluster_id.in_(cluster_ids or [0]))
        .order_by(
            CustomerInitClusterMember.cluster_id.asc(),
            CustomerInitClusterMember.is_anchor.desc(),
            CustomerInitClusterMember.match_score.desc(),
            CustomerInitClusterMember.id.asc(),
        )
        .all()
    )
    member_map: dict[int, list[CustomerInitClusterMember]] = {}
    for member in member_rows:
        member_map.setdefault(int(member.cluster_id), []).append(member)
    customer_ids = [int(row.master_customer_id or 0) for row in rows if int(row.master_customer_id or 0) > 0]
    customer_map = {
        int(row.id): row
        for row in db.query(MasterCustomer).filter(MasterCustomer.id.in_(customer_ids or [0])).all()
    } if customer_ids else {}
    out: list[dict[str, object]] = []
    for row in rows:
        members = list(member_map.get(int(row.id), []))
        customer = customer_map.get(int(row.master_customer_id or 0))
        ai_decision = decision_map.get(int(row.id))
        ai_output = ai_decision_output(ai_decision) if ai_decision else {}
        ai_review_item = review_map.get(int(ai_decision.id)) if ai_decision is not None else None
        out.append(
            {
                "cluster": row,
                "members": members,
                "summary": _json_dict(row.summary_json),
                "customer": customer,
                "ai_decision": ai_decision,
                "ai_output": ai_output,
                "ai_review_item": ai_review_item,
                "focus": int(focus_cluster_id or 0) == int(row.id),
            }
        )
    return out


def _customer_init_stage_refs(db: Session, customer_id: int) -> dict[str, object]:
    identities = db.query(ExternalIdentity).filter(ExternalIdentity.master_customer_id == int(customer_id)).all()
    outsmart_keys = {str(row.external_key or row.external_id or "").strip() for row in identities if _crm_normalize_key(row.system_name) == "outsmart" and str(row.external_key or row.external_id or "").strip()}
    sevdesk_keys = {str(row.external_key or row.external_id or "").strip() for row in identities if _crm_normalize_key(row.system_name) == "sevdesk" and str(row.external_key or row.external_id or "").strip()}
    outsmart_relations = (
        db.query(OutsmartRelationStage)
        .filter(or_(OutsmartRelationStage.relation_no.in_(list(outsmart_keys) or [""]), OutsmartRelationStage.debtor_no.in_(list(outsmart_keys) or [""])))
        .all()
    ) if outsmart_keys else []
    debtor_values = [
        str(row.debtor_no or row.relation_no or "").strip()
        for row in outsmart_relations
        if str(row.debtor_no or row.relation_no or "").strip()
    ]
    sevdesk_contacts = (
        db.query(SevdeskContactStage)
        .filter(or_(SevdeskContactStage.sevdesk_contact_id.in_(list(sevdesk_keys) or [""]), SevdeskContactStage.customer_number.in_(list(sevdesk_keys) or [""])))
        .all()
    ) if sevdesk_keys else []
    contact_ids = [str(row.sevdesk_contact_id or "").strip() for row in sevdesk_contacts if str(row.sevdesk_contact_id or "").strip()]
    return {
        "outsmart_relations": outsmart_relations,
        "outsmart_debtor_values": debtor_values,
        "sevdesk_contacts": sevdesk_contacts,
        "sevdesk_contact_ids": contact_ids,
    }


def _customer_outsmart_stage_workorder_rows(db: Session, customer_id: int, limit: int = 200) -> list[dict[str, object]]:
    refs = _customer_init_stage_refs(db, customer_id)
    debtor_values = list(refs.get("outsmart_debtor_values") or [])
    if not debtor_values:
        return []
    rows = (
        db.query(OutsmartWorkorderStage)
        .filter(
            or_(
                OutsmartWorkorderStage.customer_debtor_number.in_(debtor_values),
                OutsmartWorkorderStage.customer_invoice_debtor_number.in_(debtor_values),
            )
        )
        .order_by(OutsmartWorkorderStage.updated_at.desc(), OutsmartWorkorderStage.id.desc())
        .limit(limit)
        .all()
    )
    project_codes = {
        str(row.project_code or "").strip()
        for row in rows
        if str(row.project_code or "").strip()
    }
    project_rows = (
        db.query(OutsmartProjectStage)
        .filter(OutsmartProjectStage.project_code.in_(list(project_codes) or [""]))
        .all()
    ) if project_codes else []
    project_map = {str(row.project_code or "").strip(): row for row in project_rows if str(row.project_code or "").strip()}
    return [{"row": row, "project": project_map.get(str(row.project_code or "").strip())} for row in rows]


def _customer_sevdesk_stage_document_rows(db: Session, customer_id: int, limit: int = 240) -> list[dict[str, object]]:
    refs = _customer_init_stage_refs(db, customer_id)
    contact_ids = list(refs.get("sevdesk_contact_ids") or [])
    if not contact_ids:
        return []
    order_rows = (
        db.query(SevdeskOrderStage)
        .filter(SevdeskOrderStage.contact_id.in_(contact_ids))
        .order_by(SevdeskOrderStage.updated_at.desc(), SevdeskOrderStage.id.desc())
        .limit(max(limit, 20))
        .all()
    )
    invoice_rows = (
        db.query(SevdeskInvoiceStage)
        .filter(SevdeskInvoiceStage.contact_id.in_(contact_ids))
        .order_by(SevdeskInvoiceStage.updated_at.desc(), SevdeskInvoiceStage.id.desc())
        .limit(max(limit, 20))
        .all()
    )
    items: list[dict[str, object]] = []
    for row in order_rows:
        items.append(
            {
                "kind": "order_stage",
                "type_label": "Angebot / Order",
                "number_label": str(row.order_number or row.sevdesk_order_id or f"ORDER-{int(row.id)}"),
                "status_label": str(row.status or "-"),
                "row": row,
                "amount_cents": row.amount_cents,
                "event_date": row.order_date,
                "updated_at": row.updated_at or row.created_at,
            }
        )
    for row in invoice_rows:
        items.append(
            {
                "kind": "invoice_stage",
                "type_label": "Rechnung",
                "number_label": str(row.invoice_number or row.sevdesk_invoice_id or f"INVOICE-{int(row.id)}"),
                "status_label": str(row.status or "-"),
                "row": row,
                "amount_cents": row.amount_cents,
                "event_date": row.invoice_date,
                "updated_at": row.updated_at or row.created_at,
            }
        )
    items.sort(
        key=lambda item: (
            item.get("updated_at") or dt.datetime.min,
            int(getattr(item.get("row"), "id", 0) or 0),
        ),
        reverse=True,
    )
    return items[:limit]


def _customer_init_customer_summary(db: Session, customer_id: int) -> dict[str, object]:
    refs = _customer_init_stage_refs(db, customer_id)
    outsmart_relations = list(refs.get("outsmart_relations") or [])
    sevdesk_contacts = list(refs.get("sevdesk_contacts") or [])
    project_count = 0
    workorder_count = 0
    debtor_values = list(refs.get("outsmart_debtor_values") or [])
    if outsmart_relations:
        if debtor_values:
            project_count = int(db.query(OutsmartProjectStage).filter(or_(OutsmartProjectStage.debtor_number.in_(debtor_values), OutsmartProjectStage.debtor_number_invoice.in_(debtor_values))).count())
            workorder_count = int(db.query(OutsmartWorkorderStage).filter(or_(OutsmartWorkorderStage.customer_debtor_number.in_(debtor_values), OutsmartWorkorderStage.customer_invoice_debtor_number.in_(debtor_values))).count())
    order_count = 0
    invoice_count = 0
    if sevdesk_contacts:
        contact_ids = list(refs.get("sevdesk_contact_ids") or [])
        order_count = int(db.query(SevdeskOrderStage).filter(SevdeskOrderStage.contact_id.in_(contact_ids)).count())
        invoice_count = int(db.query(SevdeskInvoiceStage).filter(SevdeskInvoiceStage.contact_id.in_(contact_ids)).count())
    cluster = (
        db.query(CustomerInitCluster)
        .filter(CustomerInitCluster.master_customer_id == int(customer_id))
        .order_by(CustomerInitCluster.updated_at.desc(), CustomerInitCluster.id.desc())
        .first()
    )
    return {
        "cluster": cluster,
        "outsmart_relations": outsmart_relations[:3],
        "sevdesk_contacts": sevdesk_contacts[:3],
        "project_count": project_count,
        "workorder_count": workorder_count,
        "order_count": order_count,
        "invoice_count": invoice_count,
    }

