def _customer_objects_for_customer(db: Session, customer_id: int, limit: int = 80) -> list[CustomerObject]:
    return (
        db.query(CustomerObject)
        .filter(CustomerObject.master_customer_id == int(customer_id))
        .order_by(CustomerObject.updated_at.desc(), CustomerObject.id.desc())
        .limit(limit)
        .all()
    )


def _customer_objects_for_case(db: Session, row: CrmCase, limit: int = 20) -> list[CustomerObject]:
    role_map = _crm_case_role_map(db, [int(row.id)]).get(int(row.id), {})
    customer_ids = []
    service_location_id = 0
    if role_map.get(CRM_ROLE_ORDERING_PARTY) and int(role_map.get(CRM_ROLE_ORDERING_PARTY).master_customer_id or 0) > 0:
        customer_ids.append(int(role_map.get(CRM_ROLE_ORDERING_PARTY).master_customer_id))
    if role_map.get(CRM_ROLE_INVOICE_RECIPIENT) and int(role_map.get(CRM_ROLE_INVOICE_RECIPIENT).master_customer_id or 0) > 0:
        customer_ids.append(int(role_map.get(CRM_ROLE_INVOICE_RECIPIENT).master_customer_id))
    if role_map.get(CRM_ROLE_SERVICE_LOCATION) and int(role_map.get(CRM_ROLE_SERVICE_LOCATION).service_location_id or 0) > 0:
        service_location_id = int(role_map.get(CRM_ROLE_SERVICE_LOCATION).service_location_id)
    query = db.query(CustomerObject)
    if service_location_id > 0:
        query = query.filter(or_(CustomerObject.service_location_id == service_location_id, CustomerObject.master_customer_id.in_(customer_ids or [0])))
    elif customer_ids:
        query = query.filter(CustomerObject.master_customer_id.in_(customer_ids))
    else:
        return []
    return query.order_by(CustomerObject.updated_at.desc(), CustomerObject.id.desc()).limit(limit).all()


def _customer_outsmart_workorder_rows(db: Session, customer_id: int, limit: int = 80) -> list[dict[str, object]]:
    rows = (
        db.query(OutsmartWorkorder)
        .filter(OutsmartWorkorder.master_customer_id == int(customer_id))
        .order_by(OutsmartWorkorder.updated_at.desc(), OutsmartWorkorder.id.desc())
        .limit(limit)
        .all()
    )
    case_ids = [int(row.case_id) for row in rows if int(row.case_id or 0) > 0]
    object_ids = [int(row.customer_object_id) for row in rows if int(row.customer_object_id or 0) > 0]
    case_map = {int(row.id): row for row in db.query(CrmCase).filter(CrmCase.id.in_(case_ids)).all()} if case_ids else {}
    object_map = {int(row.id): row for row in db.query(CustomerObject).filter(CustomerObject.id.in_(object_ids)).all()} if object_ids else {}
    items: list[dict[str, object]] = []
    for row in rows:
        crm_case = case_map.get(int(row.case_id or 0))
        customer_object = object_map.get(int(row.customer_object_id or 0))
        display = _outsmart_prepare_workorder_view(row)
        object_label = ""
        object_meta = ""
        if customer_object:
            object_label = _crm_clean_text(
                " ".join(
                    [
                        str(customer_object.brand_label or "").strip(),
                        str(customer_object.model_label or customer_object.type_label or "").strip(),
                    ]
                )
            ) or _crm_clean_text(customer_object.external_object_code) or "Lokales Objekt"
            object_meta = _crm_clean_text(customer_object.serial_no) or ""
        elif str(display.get("device_label") or "").strip():
            object_label = str(display.get("device_label") or "").strip()
            object_meta = _crm_clean_text(display.get("object_code")) or ""
        case_hint = ""
        if crm_case is None:
            ref_parts = [str(display.get("job_no") or "").strip(), str(display.get("reference") or "").strip()]
            ref_parts = [part for part in ref_parts if part]
            if ref_parts:
                case_hint = f"OutSmart-Referenz: {' / '.join(ref_parts)}"
        items.append(
            {
                "row": row,
                "crm_case": crm_case,
                "customer_object": customer_object,
                "display": display,
                "object_label": object_label or "Kein Objekt verknüpft",
                "object_meta": object_meta,
                "case_hint": case_hint,
            }
        )
    return items


def _outsmart_candidate_cases_for_workorder(db: Session, row: OutsmartWorkorder, limit: int = 12) -> list[dict[str, object]]:
    query = db.query(CrmCase).distinct()
    if int(row.service_location_id or 0) > 0:
        query = query.join(RoleAssignment, RoleAssignment.case_id == CrmCase.id).filter(
            RoleAssignment.role_type == CRM_ROLE_SERVICE_LOCATION,
            RoleAssignment.service_location_id == int(row.service_location_id),
        )
    elif int(row.master_customer_id or 0) > 0:
        query = query.join(RoleAssignment, RoleAssignment.case_id == CrmCase.id).filter(
            RoleAssignment.role_type.in_((CRM_ROLE_ORDERING_PARTY, CRM_ROLE_INVOICE_RECIPIENT)),
            RoleAssignment.master_customer_id == int(row.master_customer_id),
        )
    else:
        return []
    rows = query.order_by(CrmCase.updated_at.desc(), CrmCase.id.desc()).limit(limit).all()
    role_map = _crm_case_role_map(db, [int(item.id) for item in rows]) if rows else {}
    customer_ids = []
    for item in rows:
        assignments = role_map.get(int(item.id), {})
        if assignments.get(CRM_ROLE_ORDERING_PARTY) and int(assignments.get(CRM_ROLE_ORDERING_PARTY).master_customer_id or 0) > 0:
            customer_ids.append(int(assignments.get(CRM_ROLE_ORDERING_PARTY).master_customer_id))
    customer_labels = _crm_customer_labels_map(db, sorted(set(customer_ids))) if customer_ids else {}
    out: list[dict[str, object]] = []
    for item in rows:
        assignments = role_map.get(int(item.id), {})
        ordering = assignments.get(CRM_ROLE_ORDERING_PARTY)
        service = assignments.get(CRM_ROLE_SERVICE_LOCATION)
        out.append(
            {
                "row": item,
                "status_label": _crm_case_status_label(item.status),
                "customer_label": customer_labels.get(int(ordering.master_customer_id or 0), "") if ordering else "",
                "service_location": db.get(ServiceLocation, int(service.service_location_id or 0)) if service and int(service.service_location_id or 0) > 0 else None,
            }
        )
    return out


def _outsmart_workorder_case_title(row: OutsmartWorkorder, display: dict[str, object]) -> str:
    parts = [
        str(display.get("device_label") or "").strip(),
        str(display.get("customer_issue") or "").strip(),
    ]
    title = _crm_clean_text(" | ".join([part for part in parts if part]))
    if title:
        return title[:240]
    return _crm_clean_text(str(display.get("short_description") or "")) or f"OutSmart-Arbeitsauftrag {row.workorder_no}"


def _outsmart_link_workorder_to_case(
    db: Session,
    *,
    row: OutsmartWorkorder,
    crm_case: CrmCase,
    source_label: str,
) -> None:
    role_map = _crm_case_role_map(db, [int(crm_case.id)]).get(int(crm_case.id), {})
    ordering = role_map.get(CRM_ROLE_ORDERING_PARTY)
    service = role_map.get(CRM_ROLE_SERVICE_LOCATION)
    if ordering and int(ordering.master_customer_id or 0) > 0:
        row.master_customer_id = int(ordering.master_customer_id)
    if service and int(service.service_location_id or 0) > 0:
        row.service_location_id = int(service.service_location_id)
    row.case_id = int(crm_case.id)
    row.updated_at = _utcnow_naive()
    db.add(row)
    _upsert_external_link(
        db,
        system_name="outsmart",
        object_type="crm_case_workorder",
        object_id=int(crm_case.id),
        external_key=str(row.workorder_no),
        external_row_id=row.external_row_id,
        deep_link_url=row.deep_link_url,
    )
    _crm_add_timeline_event(
        db,
        case_id=int(crm_case.id),
        master_customer_id=int(row.master_customer_id or 0) or None,
        service_location_id=int(row.service_location_id or 0) or None,
        customer_object_id=int(row.customer_object_id or 0) or None,
        outsmart_workorder_id=int(row.id),
        source_system="outsmart",
        event_type="workorder_link",
        title=f"OutSmart Arbeitsauftrag verknüpft: {row.workorder_no}",
        body=source_label,
        event_ts=row.scheduled_start or _utcnow_naive(),
        external_ref=row.external_row_id or row.workorder_no,
        meta={"deep_link_url": row.deep_link_url or "", "case_no": crm_case.case_no},
    )


def _outsmart_create_local_case_from_workorder(db: Session, row: OutsmartWorkorder, display: dict[str, object]) -> CrmCase:
    customer = db.get(MasterCustomer, int(row.master_customer_id or 0)) if int(row.master_customer_id or 0) > 0 else None
    service_location = db.get(ServiceLocation, int(row.service_location_id or 0)) if int(row.service_location_id or 0) > 0 else None
    if service_location and not customer and int(service_location.master_customer_id or 0) > 0:
        customer = db.get(MasterCustomer, int(service_location.master_customer_id))
    if customer is None:
        raise ValueError("Zum Arbeitsauftrag ist kein lokaler Kunde verknüpft.")
    if service_location is None:
        service_location = _crm_default_location_for_customer(db, int(customer.id))
    row_case = CrmCase(
        case_no=_crm_next_case_no(db),
        title=_outsmart_workorder_case_title(row, display),
        status=_outsmart_status_to_case_status(row.status),
        priority="normal",
        source_system="outsmart",
        note=_crm_clean_text(
            "\n".join(
                [
                    f"OutSmart-Arbeitsauftrag: {row.workorder_no}",
                    f"OutSmart-Job: {display.get('job_no') or '-'}",
                    f"Referenz: {display.get('reference') or '-'}",
                    "",
                    str(display.get("customer_issue") or "").strip(),
                    "",
                    str(display.get("work_steps") or display.get("other_notes") or "").strip(),
                ]
            )
        ) or None,
        created_at=_utcnow_naive(),
        updated_at=_utcnow_naive(),
    )
    db.add(row_case)
    db.flush()
    _, default_map = _crm_party_address_maps(db, [int(customer.party_id)])
    default_address = default_map.get(int(customer.party_id))
    _crm_set_case_role(
        db,
        crm_case_id=int(row_case.id),
        role_type=CRM_ROLE_ORDERING_PARTY,
        master_customer_id=int(customer.id),
        address_id=int(default_address.id) if default_address else None,
    )
    _crm_set_case_role(
        db,
        crm_case_id=int(row_case.id),
        role_type=CRM_ROLE_INVOICE_RECIPIENT,
        master_customer_id=int(customer.id),
        address_id=int(default_address.id) if default_address else None,
    )
    if service_location:
        _crm_set_case_role(
            db,
            crm_case_id=int(row_case.id),
            role_type=CRM_ROLE_SERVICE_LOCATION,
            master_customer_id=int(service_location.master_customer_id or 0) or None,
            service_location_id=int(service_location.id),
            address_id=int(service_location.address_id or 0) or None,
        )
    _outsmart_link_workorder_to_case(
        db,
        row=row,
        crm_case=row_case,
        source_label="Lokaler Vorgang aus OutSmart-Arbeitsauftrag angelegt.",
    )
    return row_case


def _customer_sevdesk_document_rows(db: Session, customer_id: int, limit: int = 80) -> list[dict[str, object]]:
    offer_rows = (
        db.query(OfferDraft)
        .filter(OfferDraft.master_customer_id == int(customer_id))
        .order_by(OfferDraft.updated_at.desc(), OfferDraft.id.desc())
        .limit(max(limit, 20))
        .all()
    )
    invoice_rows = (
        db.query(InvoiceDraft)
        .filter(InvoiceDraft.master_customer_id == int(customer_id))
        .order_by(InvoiceDraft.updated_at.desc(), InvoiceDraft.id.desc())
        .limit(max(limit, 20))
        .all()
    )
    case_ids = [int(row.case_id) for row in offer_rows if int(row.case_id or 0) > 0] + [int(row.case_id) for row in invoice_rows if int(row.case_id or 0) > 0]
    case_map = {int(row.id): row for row in db.query(CrmCase).filter(CrmCase.id.in_(case_ids)).all()} if case_ids else {}
    offer_link_rows = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == "sevdesk",
            ExternalLink.object_type == "offer_draft",
            ExternalLink.object_id.in_([int(row.id) for row in offer_rows] or [0]),
        )
        .all()
    ) if offer_rows else []
    invoice_link_rows = (
        db.query(ExternalLink)
        .filter(
            ExternalLink.system_name == "sevdesk",
            ExternalLink.object_type == "invoice_draft",
            ExternalLink.object_id.in_([int(row.id) for row in invoice_rows] or [0]),
        )
        .all()
    ) if invoice_rows else []
    offer_links = {int(row.object_id or 0): row for row in offer_link_rows}
    invoice_links = {int(row.object_id or 0): row for row in invoice_link_rows}
    items: list[dict[str, object]] = []
    for row in offer_rows:
        items.append(
            {
                "kind": "offer",
                "type_label": "Angebot",
                "row": row,
                "crm_case": case_map.get(int(row.case_id or 0)),
                "status_label": _offer_status_label(row.status),
                "number_label": str(row.sevdesk_order_number or f"ANG-{int(row.id):04d}"),
                "detail_url": f"/crm/angebote/{int(row.id)}",
                "pdf_url": str(row.pdf_url_local or "").strip(),
                "external_url": str((offer_links.get(int(row.id)).deep_link_url if offer_links.get(int(row.id)) else "") or "").strip(),
                "updated_at": row.updated_at or row.created_at,
            }
        )
    for row in invoice_rows:
        items.append(
            {
                "kind": "invoice",
                "type_label": "Rechnung",
                "row": row,
                "crm_case": case_map.get(int(row.case_id or 0)),
                "status_label": _invoice_draft_status_label(row.status),
                "number_label": str(row.sevdesk_invoice_number or f"RE-ENTW-{int(row.id):04d}"),
                "detail_url": f"/crm/rechnungen/{int(row.id)}",
                "pdf_url": str(row.pdf_url_local or "").strip(),
                "external_url": str((invoice_links.get(int(row.id)).deep_link_url if invoice_links.get(int(row.id)) else "") or "").strip(),
                "updated_at": row.updated_at or row.created_at,
            }
        )
    items.sort(
        key=lambda item: (
            item.get("updated_at") or dt.datetime.min,
            int(getattr(item.get("row"), "id", 0) or 0),
        ),
        reverse=True,
    )
    return items[:limit]


def _outsmart_sync_completed_once(db: Session, limit: int = 20) -> dict[str, int]:
    settings = _outsmart_settings(db, include_secret=True)
    if not bool(settings.get("enabled")):
        return {"fetched": 0, "matched": 0, "updated": 0}
    if not bool(settings.get("token")) or not bool(settings.get("software_token")):
        return {"fetched": 0, "matched": 0, "updated": 0}
    job = _start_sync_job(db, system_name="outsmart", direction="pull", entity_type="workorder", log_text="Abgeschlossene Workorders abrufen")

    fetched = 0
    matched = 0
    updated = 0
    rows = outsmart_get_completed_workorders(settings, limit=max(1, int(limit)))
    fetched = len(rows)

    for row in rows[: max(1, int(limit))]:
        work_no = str(
            row.get("WorkorderNo")
            or row.get("workorder_no")
            or row.get("repair_no")
            or row.get("reference")
            or ""
        ).strip()
        row_id = str(row.get("row_id") or row.get("RowId") or row.get("id") or "").strip()
        if not work_no:
            continue
        order = (
            db.query(RepairOrder)
            .filter(func.upper(func.coalesce(RepairOrder.repair_no, "")) == work_no.upper())
            .one_or_none()
        )
        if not order:
            continue
        matched += 1
        _upsert_external_link(
            db,
            system_name="outsmart",
            object_type="repair_order",
            object_id=int(order.id),
            external_key=work_no,
            external_row_id=row_id or None,
        )

        ref = row_id or work_no
        exists = (
            db.query(RepairEvent)
            .filter(
                RepairEvent.repair_order_id == int(order.id),
                RepairEvent.event_type == "integration",
                RepairEvent.title.like(f"%{ref}%"),
            )
            .count()
            > 0
        )
        if exists:
            continue

        detail_payload = row
        if row_id:
            try:
                detail_payload = outsmart_mark_workorder_processed(settings, row_id)
            except Exception:
                detail_payload = row

        _repair_add_event(
            db,
            order,
            "integration",
            title=f"OutSmart Rückmeldung abgeschlossen: {ref}",
            body="Workorder wurde als abgeschlossen gemeldet.",
            meta={"outsmart": detail_payload},
        )
        if str(order.status or "").strip().upper() in (
            REPAIR_STATUS_BEAUFTRAGT,
            REPAIR_STATUS_IN_REPARATUR,
            REPAIR_STATUS_ANGEFRAGT,
            REPAIR_STATUS_WARTET,
        ):
            _repair_set_status(
                db,
                order,
                REPAIR_STATUS_REPARIERT,
                title="Status auf Repariert gesetzt (OutSmart)",
                outcome=REPAIR_OUTCOME_REPARIERT,
            )
        db.add(order)
        updated += 1

    _finish_sync_job(
        db,
        job,
        status="done",
        log_text=f"gelesen={fetched}, zugeordnet={matched}, aktualisiert={updated}",
    )
    return {"fetched": fetched, "matched": matched, "updated": updated}


def _loadbee_secret_path() -> Path:
    dirs = ensure_dirs()
    return dirs["secrets"] / "loadbee_api_key.enc"


def _read_loadbee_api_key() -> str:
    secret_file = _loadbee_secret_path()
    if secret_file.is_file():
        try:
            token = (secret_file.read_text(encoding="utf-8") or "").strip()
            if token:
                return get_fernet().decrypt(token.encode("utf-8")).decode("utf-8").strip()
        except Exception:
            pass
    return (os.environ.get("LOADBEE_API_KEY") or "").strip()


def _write_loadbee_api_key(api_key: str) -> None:
    value = (api_key or "").strip()
    if not value:
        return
    secret_file = _loadbee_secret_path()
    token = get_fernet().encrypt(value.encode("utf-8")).decode("utf-8")
    secret_file.write_text(token, encoding="utf-8")
    try:
        os.chmod(secret_file, 0o600)
    except Exception:
        pass


def _loadbee_settings(db: Session, include_secret: bool = False) -> dict[str, str | bool]:
    enabled_raw = _system_setting_get(db, LOADBEE_SETTING_ENABLED, None)
    locales = (_system_setting_get(db, LOADBEE_SETTING_LOCALES, "de_DE") or "de_DE").strip() or "de_DE"
    api_key = _read_loadbee_api_key()
    load_mode_raw = _system_setting_get(db, LOADBEE_SETTING_LOAD_MODE, None)
    if load_mode_raw is None:
        load_mode = "auto" if api_key else "on_demand"
    else:
        load_mode = str(load_mode_raw or "on_demand").strip().lower()
    if load_mode not in ("on_demand", "auto"):
        load_mode = "on_demand"
    debug_mode = _bool_from_setting(_system_setting_get(db, LOADBEE_SETTING_DEBUG, "0"), default=False)
    if enabled_raw is None:
        enabled = bool(api_key)
    else:
        enabled = _bool_from_setting(enabled_raw, default=False)
    return {
        "enabled": enabled,
        "api_key_set": bool(api_key),
        "api_key": api_key if include_secret else "",
        "locales": locales,
        "load_mode": load_mode,
        "debug": debug_mode,
    }


def _normalize_loadbee_gtin(raw: str | None) -> str | None:
    cleaned = "".join(str(raw or "").split()).replace("-", "")
    return cleaned or None


